import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as s,a as e}from"./app-0abf0765.js";const t={},o=e(`<h1 id="java-alapjai" tabindex="-1"><a class="header-anchor" href="#java-alapjai" aria-hidden="true">#</a> Java alapjai</h1><p>A Java megjelenése óta a világ egyik leggyakrabban alkalmazott és legnépszerűbb programnyelvévé nőtte ki magát, a szoftverfejlesztés egyik legnépszerűbb platformja, amelyet számos területen használnak. Ez főként annak köszönhető, hogy egy jól átgondolt, gondosan felépített, és azóta is állandóan bővített és fejlesztett nyelvről van szó, mellyel elkészített programjaink tetszőleges operációs rendszeren módosítás nélkül futnak. A keretrendszerek többsége nyíltforráskódú és ez is hozzájárul a széleskörű elterjedéséhez.</p><p>A Java nyelv ismerete ma már az informatikai alapműveltség része. Az óra célja, hogy bemutassa a nyelv legfontosabb elemeit és szolgáltatásait, és segítse azok elsajátítását. Az óraszám korlátozása miatt csak a legfontosabb témákat érintjük.</p><p>A Java nyelv bemutatását az alapoktól kezdjük ezért nem szükséges semmilyen előismeret. A fejezeteket úgy választottam meg, hogy folyamatos gondolatmenetet kövessen és építsen egymásra. Az órai anyag GitHub weboldalról tölthető majd le és könnyedén az Eclipse fejlesztő környezetbe importálható.</p><div class="hint-container tip"><p class="hint-container-title">AZ ÓRA CÉLJA</p><p>Bemutassa a nyelv legfontosabb elemeit és szolgáltatásait és segítse azok elsajátítását!</p></div><h2 id="a-java-technologia-a-java-nyelv-jellemzoi" tabindex="-1"><a class="header-anchor" href="#a-java-technologia-a-java-nyelv-jellemzoi" aria-hidden="true">#</a> A Java technológia, a Java nyelv jellemzői</h2><h3 id="a-java-technologia" tabindex="-1"><a class="header-anchor" href="#a-java-technologia" aria-hidden="true">#</a> A Java technológia</h3><p>A Java programozási nyelvet a <strong>Sun Microsystems</strong> fejlesztette ki, majd dobta piacra az 1990‑es évek<br> közepén. <strong>James Gosling</strong> – a projekt indítója a Sunnál, akit a Java atyjának is tekintenek – eredetileg<br> az Oak (tölgy) nevet szerette volna az új nyelvnek adni, ám ilyen nevű programozási nyelv akkor már<br> létezett. Mivel a nyelv kifejlesztői a projekt során igen jelentős mennyiségű kávét megittak, az elfogyasztott<br> babkávé pedig Jáva szigetéről származott, a legenda szerint a nyelvet végül a sziget után nevezték<br> el.</p><p>A Java szó azonban nemcsak egy programozási nyelvet, hanem egy Java programot ír meg<br> és futtatásához szükséges szoftverkörnyezetet, vagyis egy <strong>Java platformot</strong>. A platform része a Java<br> program, Java fordító és a programokat futtató virtuális gép. A programokat egy <strong>JVM(Java<br> Virtual Machine)</strong> futtatja a számítógépet, így biztosítja a hardvertől és az operációs rendszer rendszertől<br> függetlenséget.</p><p>A platform részét képezi továbbá egy igen bő és sokoldalú fejlesztői programcsomag, a <strong>Java SDK (Software Development Kit)</strong>, vagy ahogy újabban hívják: <strong>JDK (Java Development Kit)</strong> is, melyben előre<br> kidolgozott és szabadon felhasználható komponenseket és könyvtárakat találunk.</p><p>Gyakran találkozhatunk olyan kifejezésekkel, amelyek tartalmazzák a Java szót - ezek egy része valóban<br> a Java rész, mások azonban csak névrokonok. <strong>JavaScript</strong> egy a <strong>Netscape</strong> által kifejlesztett script nyelv, és bár ez egy böngésző értelmezi, ez semmi köze a Java-hoz technológiához.</p><h3 id="a-java-nyelv-jellemzoi" tabindex="-1"><a class="header-anchor" href="#a-java-nyelv-jellemzoi" aria-hidden="true">#</a> A Java nyelv jellemzői</h3><p>A Java egy <strong>magas szintű</strong>, teljesen <strong>objektumorientált nyelv</strong> - alapjaitól eszerint építették fel. A<br> Javában néhány beépített egyszerű típusról eltekintve <strong>minden objektum</strong>: karakterlánc, programhiba,<br> maga a Java program. Nincsenek globális változók és függvények: <em>minden adat és művelet valamilyen objektumhoz kötődik.</em></p><p>A Java egy másik fontos tulajdonsága a <strong>platformfüggetlenség</strong>. Ez azt jelenti más és más operációs rendszeren is változtatás nélkül képes futni. Ezt úgy oldották meg, hogy a fordítóprogram csak ún. <strong>Java bájtkód</strong>ra fordítja le a forráskódot ezt kapja meg a <strong>virtuális gép (JVM)</strong>, és csak ő fordítja le azt gépi kódra. Mivel a programból csak futás közben lesz gépi kód, a <strong>Java interpretált nyelv.</strong></p><p>Szintaktikája a C++-t követi, de sok figyelmet fordítottak arra, hogy biztonságos és megbízható nyelvet építsenek. Így a Javában nincs <strong>goto</strong> (ugrás) utasítás, nincsenek <strong>mutatók</strong> (pointerek), nincs <strong>többszörös öröklődés</strong>, nincs <strong>rekordtípus</strong>, és az operátorok nem felüldefiniálhatóak <em>(operator overloading)</em>.</p><p>Van benne viszont automatikus szemétgyűjtés <em>(Garbage Collector)</em>: a nyelv automatikusan felszabadítja a már nem használt erőforrásokat. <strong>Támogatja</strong> a többszálú, illetve a hálózati programozást, és távoli gépeken is képes biztonságosan futni. A <strong>JDK</strong> implementál számos gyakran használt adatszerkezetet <em>(halmaz, lista, verem, hashtábla)</em>, hasznos algoritmusokat <em>(rendezések, minimumkeresés)</em>, és szinte minden műveletet, amire például matematikai számítások elvégzéséhez vagy sztringek és dátumok feldolgozása során szükségünk lehet.</p><h2 id="a-java-program-szerkezete-elemi-output" tabindex="-1"><a class="header-anchor" href="#a-java-program-szerkezete-elemi-output" aria-hidden="true">#</a> A Java program szerkezete, elemi output</h2><h3 id="elso-java-programunk-hello-world" tabindex="-1"><a class="header-anchor" href="#elso-java-programunk-hello-world" aria-hidden="true">#</a> Első Java programunk: Hello World</h3><p>A <strong>Java főprogram</strong> kódja mindig egy speciális osztály <strong>main metódusának</strong> kidolgozása lesz. A forráskódot egy <strong>.java</strong> kiterjesztésű állományba mentjük, mely állomány neve meg kell, hogy egyezzen a benne található osztály nevével.</p><div class="hint-container tip"><p class="hint-container-title">INFO</p><p>Egy nyelvvel való ismerkedést a „Hello World” alkalmazás megírásával szokás kezdeni, amely semmi egyebet nem csinál, mint kiírja a képernyőre az üdvözlőüzenetet.</p></div><p>Nézzük meg, hogyan néz ki Javában a „Hello World” program, amelyet a <strong>HelloWorld.java</strong> fájlba mentünk el.</p><h4 id="helloworld-java" tabindex="-1"><a class="header-anchor" href="#helloworld-java" aria-hidden="true">#</a> HelloWorld.java</h4><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">HelloWorld</span> <span class="token punctuation">{</span>

	<span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token comment">// Prints &quot;Hello, World&quot; to the terminal window.</span>
		<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Hello, World&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
	<span class="token punctuation">}</span>

<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A main metódus azonosítója mögött zárójelben az alábbi kifejezés található: <strong>String[] args</strong>. Ez egy<br> karakterláncokat tartalmazó, args nevű tömböt jelöl. Az args tömb segítségével kapjuk meg azon <strong>paramétereket</strong>,<br> melyekkel a felhasználó a programot elindította.</p><p>Egy program paramétereit parancssorból indításkor a futtatandó állomány neve mögé kell gépelni, egymástól szóközzel elválasztva. A program pedig egyetlen sorból áll: <strong>System.out.println(&quot;Hello, World!&quot;);</strong>. A println metódussal<br> tudunk tehát üzenetet megjeleníteni a képernyőn; a println metódus a szöveg kiírása után sort is emel.</p><h2 id="osszefoglalo" tabindex="-1"><a class="header-anchor" href="#osszefoglalo" aria-hidden="true">#</a> Összefoglaló</h2><div class="hint-container tip"><p class="hint-container-title">Mi a különbség a Java nyelv és a Java platform között?</p><p>A Java szó azonban nem csak egy programozási nyelvet jelöl, hanem a Java programok megírásához és futtatásához szükséges szoftverkörnyezetet, azaz a Java platformot is.<br> A platform része a Java program, a Java fordító, és a programokat futtató virtuális gép is.<br> A platform részét képezi továbbá egy igen bő és sokoldalú fejlesztői programcsomag, a Java SDK (Software Development Kit), vagy ahogy újabban hívják: JDK (Java Development Kit) is, melyben előre kidolgozott és szabadon felhasználható komponenseket és könyvtárakat találunk.</p></div><div class="hint-container tip"><p class="hint-container-title">Mi a JVM, és mi a szerepe?</p><p>A Java egy másik fontos tulajdonsága a platformfüggetlenség, más néven hordozhatóság. ez azt jelenti, hogy ugyanaz a program különböző hardveren, más és más operációs rendszeren is változtatás nélkül képes futni. A Java esetében ezt úgy oldották meg, hogy a fordítóprogram csak ún. Java bájtkódra fordítja le a forráskódot – ezt kapja meg a virtuális gép (JVM), és csak ő fordítja le azt gépi kódra (értelemszerűen az adott „gép” által értelmezhető gépi kódra). mivel a programból csak futás közben lesz gépi kód, a Java interpretált nyelv.</p></div><div class="hint-container tip"><p class="hint-container-title">Java programozási nyelv legfontosabb jellemzőit!</p><ul><li>magas szintű, teljesen objektumorientált nyelv platformfüggetlen</li><li>megbízható, avagy robusztus</li><li>biztonságos</li><li>szintaktikája a C++-t követi</li></ul></div><h2 id="azonositok-egyszeru-tipusok" tabindex="-1"><a class="header-anchor" href="#azonositok-egyszeru-tipusok" aria-hidden="true">#</a> Azonosítók, egyszerű típusok</h2><h3 id="azonositok" tabindex="-1"><a class="header-anchor" href="#azonositok" aria-hidden="true">#</a> Azonosítók</h3><p>Azonosítónak nevezzük egy Java programban a változók, metódusok, osztályok, stb. egyedi elnevezéseit. Az azonosítók meghatározásánál pár egyszerű szabályt be kell tartanunk.</p><div class="hint-container tip"><p class="hint-container-title">SZABÁLYOK</p><p>Az azonosítónak betűvel kell kezdődnie. Betű alatt az angol ábécé betűit és a _ és $ karaktereket értjük.<br> Az azonosítók a második karaktertől a fentiek mellett számokat is tartalmazhatnak.<br> Az azonosító nem lehet foglalt szó.</p></div><p>Bár a Java megengedi a magyar ékezetes karakterek használatát is, azonosítóinkban ezeket inkább ne használjuk. <strong>Foglalt</strong> szónak nevezzük azokat az azonosítókat, melyeket a nyelv írói saját kulcsszavaik elnevezésére használtak.</p><div class="hint-container tip"><p class="hint-container-title">JAVA FOGLALT SZAVAI</p><p>abstract, boolean, break, byte, case, catch, char, class, const, continue, default, do, double, else, extends, final, finally, float, for, goto, if, implements, import, instanceof, int, interface, long, native, new, package, private, protected, public, return, short, static, super, switch, synchronized, this, throw, throws, transient, try, void, volatile, while</p></div><p>Az azonosító hossza tetszőleges lehet, ezért használjunk beszédes neveket. Szintaktikai hibát ugyan nem okoz, ha ezt az íratlan szabályt nem tartjuk be, de a beszédes nevekkel segítjük a program érthetőségét és olvashatóságát. Bár a nyelv maga igen nagy szabadságot enged az azonosítók meghatározásánál, bizonyos konvenciókat valamennyi Java fejlesztő be szokott tartani. Így például a konstansok azonosítóit csupa nagybetűvel szokás írni. Az ilyen elnevezési konvenciókat a megfelelő helyen részletezzük majd.</p><h3 id="egyszeru-tipusok" tabindex="-1"><a class="header-anchor" href="#egyszeru-tipusok" aria-hidden="true">#</a> Egyszerű típusok</h3><p>Az <strong>adattípus</strong> meghatározza, hogy egy adat milyen értékeket vehet fel, és milyen műveleteket végezhetünk el vele. <strong>Egyszerű típus</strong>nak nevezzük azokat az adattípusokat, melyek nem bonthatók további részekre. Ilyenek például a logikai, karakteres, egész és valós szám típusok. Ezzel szemben az <strong>összetett adattípus</strong>ok egyszerű típusokból épülnek fel. Ilyenek a tömbök, a különböző listatípusok.</p><p>Mint a legtöbb programozási nyelvben, a Javában is léteznek egyszerű típusok. Egy karakternek is értékül adhatunk számkaraktert (pl. a 2-es szám karaktermegfelelőjét), ám ebben az esetben karakterként viselkedik. Tehát matematikai műveleteket nem végezhetünk rajta, pl. nem szorozhatjuk meg egy másik számmal.</p><table><thead><tr><th><strong>egyszerű típus</strong></th><th><strong>Leírása</strong></th><th><strong>Lehetséges értékei</strong></th></tr></thead><tbody><tr><td><strong>boolean</strong></td><td>Logikai típus</td><td><strong>true</strong> (igaz), <strong>false</strong> (hamis)</td></tr><tr><td><strong>char</strong></td><td>Karakter típus</td><td>a, b, C, é, 2, $, *, @, ...</td></tr><tr><td><strong>byte</strong></td><td>1 bájton tárolt egész szám típus</td><td>-128 ... 127</td></tr><tr><td><strong>short</strong></td><td>Rövid egész szám típus</td><td>-32768 .. 32767</td></tr><tr><td><strong>int</strong></td><td>Egész szám típus</td><td>-2*109 .. 2*109</td></tr><tr><td><strong>long</strong></td><td>hosszú egész szám típus</td><td>-1019 .. 1019</td></tr><tr><td><strong>float</strong></td><td>Lebegőpontos valós szám típus</td><td>2.5, 3.14</td></tr><tr><td><strong>double</strong></td><td>Lebegőpontos valós szám típus</td><td>2.5, 3.14</td></tr></tbody></table><h2 id="valtozodeklaracio-inicializalas-es-literalok-konstansok" tabindex="-1"><a class="header-anchor" href="#valtozodeklaracio-inicializalas-es-literalok-konstansok" aria-hidden="true">#</a> Változódeklaráció, inicializálás és literálok, konstansok</h2><h3 id="valtozodeklaracio" tabindex="-1"><a class="header-anchor" href="#valtozodeklaracio" aria-hidden="true">#</a> Változódeklaráció</h3><p>Egy programban az egyes adatainkat <strong>változókban</strong> tároljuk. A programban használt változók felsorolását <strong>deklarációnak</strong> nevezzük. Egy változó deklarációjánál meg kell adnunk annak típusát és azonosítóját. Javában előbb kell megadnunk a típus nevét, majd ezt követi a deklarálandó változó neve vagy változók nevei – mivel egy utasításban több változót is létrehozhatunk. Ilyenkor az azonosítókat vesszővel választjuk el egymástól.</p><p>Az utasításokat – így a változódeklarációt is – pontosvesszővel zárjuk.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> i<span class="token punctuation">;</span>
<span class="token keyword">int</span> szam1<span class="token punctuation">,</span> szam2<span class="token punctuation">;</span> 
<span class="token keyword">char</span> ch1<span class="token punctuation">,</span> ch2<span class="token punctuation">,</span> ch3<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A fenti példában a <em>szam1</em> és <em>szam2</em> változókat két utasításban is deklarálhattuk volna, az eredmény ugyanaz lenne.</p><div class="hint-container tip"><p class="hint-container-title">VÁLTOZÓK</p><p>Az egyszerű típusú változókat kisbetűsen szokás elnevezni.</p></div><p>A Java programban nincs a változók deklarálására kijelölt blokk, a program bármelyik pontján felvehetünk újabbakat. Az áttekinthetőség kedvéért azonban érdemes pár szabályt betartanunk.</p><h3 id="inicializalas-es-literalok-konstansok" tabindex="-1"><a class="header-anchor" href="#inicializalas-es-literalok-konstansok" aria-hidden="true">#</a> Inicializálás és literálok, konstansok</h3><p>Változóink deklarálásakor azok kezdőértékét is meghatározhatjuk, mégpedig úgy, hogy a deklaráció utasításában értékadást hajtunk végre. Ezt nevezzük inicializálásnak.<br> A Javában az értékadás operátora az ’=’, mely után a változó új értékét kell megadnunk; ez lehet konkrét érték vagy másik változó.</p><p>Ha egy utasításban több változót is definiálunk, azok közül bármelyiknek adhatunk kezdőértéket.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
<span class="token keyword">int</span> szam1<span class="token punctuation">,</span> szam2 <span class="token operator">=</span> <span class="token number">100</span><span class="token punctuation">;</span>
<span class="token keyword">char</span> ch1 <span class="token operator">=</span> <span class="token char">&#39;a&#39;</span><span class="token punctuation">,</span> ch2<span class="token punctuation">,</span> ch3 <span class="token operator">=</span> <span class="token char">&#39;B&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Minden változót külön kell inicializálni, tehát példánkban a <strong>szam2</strong> kezdőértéke 100 lesz, a <strong>szam1</strong>-nek azonban nincs még értéke. A programban előforduló konkrét értékeket a Javában literálnak nevezzük. Az inicializálásban megadott kezdőértékek (pl. 1, ’B’) is literálok.</p><p>Vizsgáljuk meg, milyen lehetséges literálokat használhatunk programjainkban.</p><table><thead><tr><th><strong>Literál</strong></th><th><strong>Magyarázat</strong></th></tr></thead><tbody><tr><td>null</td><td>Üres érték, pl. inicializálatlan objektumok vagy változók értéke.</td></tr><tr><td>true, false</td><td>logikai értékek</td></tr><tr><td>0, 3, 255</td><td>Pozitív egész számok</td></tr><tr><td>-10, -12580</td><td>negatív egész számok</td></tr><tr><td>0377</td><td>Oktális (nyolcas) számrendszerben megadott szám, azaz 377(8), melynek értéke 255. Az oktális számrendszert a kezdőnulla jelöli.</td></tr><tr><td>0xff</td><td>hexadecimális számrendszerben megadott szám, azaz FF(16), melynek decimális értéke: 255. A hexadecimális számrendszert a bevezető &#39;0x&#39; jelöli.</td></tr><tr><td>123l, 123L</td><td>Long típusú szám, melynek értéke 123. A long típust a szám után írt l vagy L betű jelöli. Byte és short típushoz nincs hasonló jelölés.</td></tr><tr><td>3.141592, -15.8d</td><td>Lebegőpontos számok, melyek double típusúként értendők. A d jelző kiírása nem kötelező.</td></tr><tr><td>3.141592f</td><td>Float típusúként értelmezett lebegőpontos szám. A float típust a szám után írt f betű jelzi.</td></tr><tr><td>&#39;a&#39;, &#39;B&#39;, &#39;\\n&#39;</td><td>Karakterliterálok. A &#39;\\n&#39; a sortörés ún. escape szekvenciája.</td></tr><tr><td>&quot;alma&quot;, &quot;B&quot;</td><td>Szövegliterálok. A szövegként megadott betű nem azonos a karakterként megadott betűvel.</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">FONTOS</p><p>A fenti példában megadott karakter <strong>’B’</strong> és szöveges <strong>”B”</strong> nem azonos típusúak, így például össze nem hasonlíthatók, és karakteres változónak az utóbbi értékül nem adható.<br> Hasonlóképpen megkülönböztetendő a szám: <strong>3</strong>, a karakteres <strong>’3’</strong> vagy szöveges <strong>”3”</strong> értékek. Ez utóbbi kettő aritmetikai kifejezésben (pl. összeadás tagjaként) sem használható, és szám típusú változónak sem adható értékül.</p></div><p>Azon változónkat, melynek értéke a program futása során nem változhat, <strong>konstansnak</strong> nevezzük. Javában a <strong>final</strong> módosítószó jelzi egy változóról, ha az konstans, melyet a típus neve előtt kell megadni. Mivel a konstansok értéke a program során nem változhat, így értelemszerűen ezeket inicializálni szoktuk.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">final</span> <span class="token keyword">int</span> <span class="token constant">SZAZ</span> <span class="token operator">=</span> <span class="token number">100</span><span class="token punctuation">;</span>
<span class="token keyword">final</span> <span class="token keyword">char</span> <span class="token constant">ABETU</span> <span class="token operator">=</span> <span class="token char">&#39;a&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">final</span> <span class="token keyword">float</span> <span class="token constant">PI</span> <span class="token operator">=</span> <span class="token number">3.141592</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">KONSTANS</p><p>A konstansok azonosítóit Javában csupa nagybetűvel szokás írni, ezáltal a kódban is jól megkülönböztethetőek a változóktól. A Java beépített konstansait is hasonlóképpen nevezték el a nyelv megalkotói.</p></div><h2 id="kifejezesek-operatorok" tabindex="-1"><a class="header-anchor" href="#kifejezesek-operatorok" aria-hidden="true">#</a> Kifejezések, operátorok</h2><p>A műveletet más néven <strong>operátornak</strong>, azokat az adatok pedig, melyekkel az operátor a műveletet végzi, <strong>operandusoknak</strong> nevezzük. Operátorokból és operandusokból tetszőleges bonyolultságú <strong>kifejezést</strong> építhetünk. Az egy operandusú műveleteket <strong>unáris</strong>, a két operandusú műveleteket <strong>bináris</strong> operátoroknak nevezzük. Nézzük meg a legfontosabb operátorokat.</p><h3 id="logikai-es-osszehasonlito-operatorok" tabindex="-1"><a class="header-anchor" href="#logikai-es-osszehasonlito-operatorok" aria-hidden="true">#</a> Logikai és összehasonlító operátorok</h3><p>A logikai és összehasonlító operátorokban az a közös, hogy az ezekből alkotott kifejezések logikai eredményt adnak.</p><table><thead><tr><th><strong>Operátor</strong></th><th><strong>Magyarázat</strong></th></tr></thead><tbody><tr><td>!</td><td>Logikai tagadás operátora (unáris)</td></tr><tr><td>&amp;&amp;</td><td>Logikai ÉS operátor</td></tr><tr><td>||</td><td>Logikai VAGY operátor</td></tr><tr><td>== , !=</td><td>Egyenlőségvizsgálat operátorok (egyenlő, nem egyenlő)</td></tr><tr><td>&lt;, &lt;=, &gt;, &gt;=</td><td>összehasonlító operátorok</td></tr></tbody></table><p>Nézzünk néhány példát a fenti operátorok alkalmazására!</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">boolean</span> igaz <span class="token operator">=</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
<span class="token keyword">boolean</span> hamis <span class="token operator">=</span> <span class="token boolean">false</span><span class="token punctuation">;</span>
<span class="token keyword">boolean</span> eredmeny<span class="token punctuation">;</span>

eredmeny <span class="token operator">=</span> <span class="token operator">!</span>igaz<span class="token punctuation">;</span> <span class="token comment">// eredmeny: false</span>
eredmeny <span class="token operator">=</span> igaz <span class="token operator">&amp;&amp;</span> hamis<span class="token punctuation">;</span> <span class="token comment">// eredmeny: false</span>
eredmeny <span class="token operator">=</span> igaz <span class="token operator">||</span> hamis<span class="token punctuation">;</span> <span class="token comment">// eredmeny: true</span>

<span class="token keyword">int</span> i<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">,</span> j<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">,</span> k<span class="token operator">=</span><span class="token number">5</span><span class="token punctuation">;</span>
eredmeny <span class="token operator">=</span> <span class="token punctuation">(</span>i <span class="token operator">&lt;</span> j<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// eredmeny: false</span>
eredmeny <span class="token operator">=</span> <span class="token punctuation">(</span>i <span class="token operator">&lt;=</span> j<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// eredmeny: true</span>
eredmeny <span class="token operator">=</span> <span class="token punctuation">(</span>i <span class="token operator">==</span> k<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// eredmeny: false</span>
eredmeny <span class="token operator">=</span> <span class="token punctuation">(</span>i <span class="token operator">!=</span> k<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// eredmeny: true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container warning"><p class="hint-container-title">FONTOS</p><p>Ne tévesszük össze az értékadás (=) operátort az egyenlőségvizsgálat (==) operátorával!</p></div><h3 id="aritmetikai-operatorok" tabindex="-1"><a class="header-anchor" href="#aritmetikai-operatorok" aria-hidden="true">#</a> Aritmetikai operátorok</h3><p>Az aritmetikai operátorokat egész vagy valós szám típusú operandusokkal használhatjuk.</p><table><thead><tr><th><strong>Operátor</strong></th><th><strong>Magyarázat</strong></th></tr></thead><tbody><tr><td>+, -</td><td>unáris: előjel (pozitív és negatív)</td></tr><tr><td>+, -</td><td>Bináris: összeadás és kivonás operátorok</td></tr><tr><td>*, /, %</td><td>Szorzás, osztás és osztási maradék (modulo) operátorok</td></tr></tbody></table><p>Nézzünk meg néhány példát a matematikai operátorok alkalmazására!</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> i<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">,</span> j<span class="token operator">=</span><span class="token number">2</span><span class="token punctuation">,</span> k<span class="token operator">=</span><span class="token number">5</span><span class="token punctuation">;</span>
<span class="token keyword">int</span> eredmeny<span class="token punctuation">;</span>
eredmeny <span class="token operator">=</span> i <span class="token operator">+</span> j<span class="token punctuation">;</span> <span class="token comment">// eredmeny: 3</span>
eredmeny <span class="token operator">=</span> k <span class="token operator">*</span> k<span class="token punctuation">;</span> <span class="token comment">// eredmeny: 25</span>
eredmeny <span class="token operator">=</span> k <span class="token operator">%</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// eredmeny: 1</span>
<span class="token keyword">float</span> hanyados <span class="token operator">=</span> k <span class="token operator">/</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// eredmeny: 2.0</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A példa utolsó sorában láthatjuk, hogy hiába definiáltunk egy hányados float típusú változót, a hányados mégis a kerekített érték lett. Ennek oka, hogy a Javában ilyenkor automatikus típuskonverzió hajtódik végre.</p><p>Mivel a <strong>k / 2</strong> kifejezésben a k egész szám, a kifejezés értéke is egész szám lesz. Ha ezt értékül adjuk egy float típusú változónak, annak típusa ugyan megváltozik, értéke azonban nem. Ilyenkor alkalmazhatjuk az explicit típuskonverziót: azaz megmondhatjuk, hogy a jobb oldali kifejezésnek mi legyen a típusa. Az explicit típuskonverzió esetében a megfelelő típus nevét a kifejezés elé kell írni zárójelek között.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> j <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">,</span> k <span class="token operator">=</span> <span class="token number">5</span><span class="token punctuation">;</span>
<span class="token keyword">float</span> hanyados <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">float</span><span class="token punctuation">)</span>k <span class="token operator">/</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// eredmeny: 2.5</span>
<span class="token keyword">byte</span> hanyados <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">byte</span><span class="token punctuation">)</span>k <span class="token operator">/</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// eredmeny: 2</span>
<span class="token keyword">double</span> hanyados <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">double</span><span class="token punctuation">)</span>k <span class="token operator">/</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// eredmeny: 2.5</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="ertekado-operatorok" tabindex="-1"><a class="header-anchor" href="#ertekado-operatorok" aria-hidden="true">#</a> Értékadó operátorok</h3><p>Java nyelv nem csupán egyféle értékadó operátort kínál. A különféle speciális értékadó utasítások alapgondolata a valt = valt + 1 típusú kifejezések egyszerűsítése, azaz amikor egy változó eredeti értékét módosítjuk az utasításban. Az értékadásban szereplő operátort összevonhatjuk az értékadással, így az előbbi értékadást így is írhatjuk: valt += 1. Az alábbi utasítások egyenértékűek a sor végén kommentben megadottal.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> valt <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span> 
valt <span class="token operator">+=</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token comment">// valt = valt + 1;</span>
valt <span class="token operator">-=</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token comment">// valt = valt - 1;</span>
valt <span class="token operator">*=</span> <span class="token number">5</span><span class="token punctuation">;</span> <span class="token comment">// valt = valt * 5;</span>
valt <span class="token operator">/=</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// valt = valt / 2;</span>
valt <span class="token operator">%=</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token comment">// valt = valt % 3;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="prefix-es-postfix-operatorok" tabindex="-1"><a class="header-anchor" href="#prefix-es-postfix-operatorok" aria-hidden="true">#</a> Prefix és postfix operátorok</h3><p>A speciális értékadó operátorokkal már egyszerűbbé tettük egy változó értékének eggyel való növelését vagy csökkentését, ám erre a célra a Javában egy még egyszerűbb mód is a rendelkezésünkre áll.<br> A ++ és – – unáris operátorok eggyel növelik vagy csökkentik az operandusként megadott változó értékét. Az alábbi utasítások egyenértékűek a sor végén kommentben megadottal.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> valt <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
valt<span class="token operator">++</span><span class="token punctuation">;</span> <span class="token comment">// valt = valt + 1; </span>
valt<span class="token operator">--</span><span class="token punctuation">;</span> <span class="token comment">// valt = valt – 1;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az eggyel csökkentő vagy növelő operátort kifejezésbe is ágyazhatjuk, mégpedig kétféleképpen. Ha <strong>prefix</strong> operátorként alkalmazzuk (pl. ++valt), akkor előbb módosul a változó értéke, és csak utána értékelődik ki a kifejezés, amely már az új értéket használja fel. <strong>Postfix</strong> operátor esetén előbb kiértékelődik a kifejezés, mely a változó eredeti értékét használja fel, majd csak ezután módosul a változó értéke.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">,</span> j <span class="token operator">=</span> <span class="token number">10</span>
<span class="token keyword">int</span> pre <span class="token operator">=</span> <span class="token operator">++</span>i <span class="token operator">+</span> j<span class="token punctuation">;</span> <span class="token comment">// pre: 13</span>
pre <span class="token operator">=</span> i<span class="token punctuation">;</span> <span class="token comment">// pre: 3</span>
pre <span class="token operator">=</span> j<span class="token punctuation">;</span> <span class="token comment">// pre: 10</span>
<span class="token keyword">int</span> post <span class="token operator">=</span> i<span class="token operator">++</span> <span class="token operator">+</span> j<span class="token operator">++</span><span class="token punctuation">;</span> <span class="token comment">// post: 13; i: 4; j: 11</span>
<span class="token keyword">int</span> post <span class="token operator">=</span> i <span class="token operator">+</span> j<span class="token punctuation">;</span> <span class="token comment">// post: 15</span>
<span class="token keyword">int</span> post <span class="token operator">=</span> <span class="token operator">--</span>i <span class="token operator">+</span> j<span class="token operator">--</span><span class="token punctuation">;</span> <span class="token comment">// post: 14</span>
<span class="token keyword">int</span> post <span class="token operator">=</span> i<span class="token punctuation">;</span> <span class="token comment">// post: 3</span>
<span class="token keyword">int</span> post <span class="token operator">=</span> j<span class="token punctuation">;</span> <span class="token comment">// post: 10</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="operatorok-kiertekelese" tabindex="-1"><a class="header-anchor" href="#operatorok-kiertekelese" aria-hidden="true">#</a> Operátorok kiértékelése</h3><div class="hint-container tip"><p class="hint-container-title">OPERÁTOROK</p><p>Az operátorok között a matematikában és egyéb programozási nyelvekben megszokott módon precedencia, azaz erősorrend érvényesül, vagyis egy összetett műveletsorban előbb mindig a nagyobb precedenciájú műveletek hajtódnak végre. A végrehajtás sorrendje zárójelezéssel befolyásolható.</p></div><p>Az eddig áttekintett operátorok precedencia-sorrendjét a következő táblázat mutatja lefelé csökkenően (az 1-es prioritású operátor értékelődik ki elsőnek):</p><table><thead><tr><th><strong>Prioritás</strong></th><th><strong>Operátor</strong></th><th><strong>Megnevezés</strong></th></tr></thead><tbody><tr><td><strong>1</strong></td><td>++, --</td><td>Prefix vagy postfix növelés és csökkentés</td></tr><tr><td></td><td>+, -</td><td>Előjelek (unáris operátorként</td></tr><tr><td></td><td>!</td><td>logikai tagadás</td></tr><tr><td><strong>2</strong></td><td>*, /, %</td><td>Szorzás, osztás, modulo</td></tr><tr><td><strong>3</strong></td><td>+, -</td><td>összeadás, kivonás (bináris operátorként)</td></tr><tr><td><strong>4</strong></td><td>&lt;, &lt;=, &gt;, &gt;=</td><td>összehasonlító operátorok</td></tr><tr><td><strong>5</strong></td><td>==, !=</td><td>Egyenlő és nem egyenlő</td></tr><tr><td><strong>6</strong></td><td>&amp;&amp;</td><td>Logikai ÉS</td></tr><tr><td><strong>7</strong></td><td>||</td><td>Logikai VAGY</td></tr><tr><td><strong>8</strong></td><td>=, +=, -=, *=, /=, %=</td><td>értékadás operátorok</td></tr></tbody></table><h2 id="utasitas-es-blokk" tabindex="-1"><a class="header-anchor" href="#utasitas-es-blokk" aria-hidden="true">#</a> Utasítás és blokk</h2><p>Az utasítás lehet deklaráció, értékadás, postfix vagy prefix operátorokkal képzett értéknövelés vagy csökkentés, illetve metódushívás. Az előző fejezetben láttunk példát deklaráció típusú utasításra.<br> Utasítások egybefüggő sorozatát nevezzük <strong>blokknak</strong>.</p><div class="hint-container warning"><p class="hint-container-title">FONTOS</p><p>Az utasítást pontosvesszővel ( ; ) zárjuk. A blokkot { és } jelek közé írjuk.</p></div><p>Minden olyan esetben, amikor utasítás írható: blokk is írható. Így ciklus magja, utasítás valamely ága is lehet egyszerű utasítás vagy ezekből képzett blokk.<br> A blokkban létrehozott változó csak a blokk végéig létezik. Az ilyen változót lokális változónak nevezzük.</p><p>Nézzük meg az alábbi példában az utasítás, blokk, illetve a lokális változó használatát!</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token punctuation">{</span>
  <span class="token keyword">int</span> i<span class="token punctuation">;</span> <span class="token comment">// i lokalis</span>
  i <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
  <span class="token keyword">int</span> j <span class="token operator">=</span> i <span class="token operator">+</span> b <span class="token comment">// j lokalis; b a blokkban nem lokalis</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">FONTOS</p><p>Blokkok egymásba ágyazásánál különösen figyeljünk oda a kód megfelelő tagolására! A blokknyitó és záró kapcsos zárójeleket mindig írjuk egy oszlopba, a blokk utasításait pedig kezdjük beljebb, egyvonalban.</p></div><h2 id="elagazas-tipusai-alkalmazasa" tabindex="-1"><a class="header-anchor" href="#elagazas-tipusai-alkalmazasa" aria-hidden="true">#</a> Elágazás típusai, alkalmazása</h2><p>Utasítások egymás után írásával képezhetünk azokból szekvenciát. Ez azonban még nem elég tetszőleges probléma megoldásának programozásához. Szükségünk lehet arra, hogy utasítások egy csoportja csak bizonyos feltétel teljesülése esetén hajtódjon végre. Az ilyen programozási struktúrát nevezzük <strong>elágazásnak</strong>.</p><h3 id="egyszeru-elagazas" tabindex="-1"><a class="header-anchor" href="#egyszeru-elagazas" aria-hidden="true">#</a> Egyszerű elágazás</h3><p><strong>Egyszerű elágazásnak</strong> nevezzük a legfeljebb két lehetséges végrehajtási ággal rendelkező elágazástípust. Egyszerű elágazás esetén meg kell adnunk egy logikai kifejezést (<strong>feltételt</strong>), illetve egy vagy két utasítást vagy blokkot: az <strong>igaz és hamis ág</strong> utasításait. Ha a feltételben megadott kifejezés teljesül, az igaz ág hajtódik végre – ennek megadása kötelező. Ha a feltétel nem teljesül, akkor a hamis ágra kerül a vezérlés, amennyiben megadtunk ilyet; ellenkező esetben a program futása az elágazást követő utasítással folytatódik.</p><p>Az egyszerű elágazás <strong>szintaktikája</strong> a következő:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>feltetel<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token comment">// Igaz ag</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token comment">// Hamis ag </span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><em>Bár a Java szintaktikai szabályai alapján, ha az elágazás valamelyik ága egyszerű utasítás (fenti példánkban mindkettő), úgy a blokknyitó és záró kapcsos zárójel elhagyható. A jobb olvashatóság érdekében azonban minden esetben ki szoktuk tenni azokat.</em></p><div class="hint-container danger"><p class="hint-container-title">FONTOS</p><p>Az elágazás végére <strong>tilos</strong> az utasítászáró pontosvesszőt kitenni!</p></div><p>Nézzünk egy <strong>példát</strong> az egyszerű elágazásra:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>b <span class="token operator">&gt;=</span> <span class="token number">100</span> <span class="token operator">&amp;&amp;</span> b <span class="token operator">&lt;</span> <span class="token number">1000</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// Feltetel</span>
    <span class="token comment">// Igaz ag </span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Haromjegyu&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token comment">// Hamis ag</span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Nem haromjegyu&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container warning"><p class="hint-container-title">FONTOS</p><p>Egyszerű elágazás esetén kövessük a fenti példa tagolását! Az elágazás feje, az <code>else</code> és a záró kapcsos zárójel azonos oszlopban kezdődjön, az egyes ágak utasításait kezdjük beljebb, egyvonalban!</p></div><p>Az <code>else</code> kulcsszó után újabb egyszerű elágazás írható, így növelhetjük a vizsgált feltételek számát és az azokhoz tartozó utasításokat.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>b <span class="token operator">&gt;=</span> <span class="token number">100</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// Feltetel</span>
    <span class="token comment">// (b &gt;= 100) Igaz ag</span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Haromjegyu&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>b <span class="token operator">&gt;=</span> <span class="token number">10</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// (b &gt;= 100) Hamis ag es (b &gt;= 10) Igaz ag</span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Ketjegyu&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token comment">// (b &gt;= 100) Hamis ag es (b &gt;= 10) Hamis ag</span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Egyjegyu&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Amennyiben <strong>egyszerű elágazásokat</strong> ágyazunk egymásba a fenti módon, az egyes ágak közül legfeljebb <strong>egy futhat le</strong>. Ha valamelyik feltétel igaz, a hozzá tartozó utasítások végrehajtása után az elágazás utáni első kódsorra kerül a vezérlés. Előfordulhat, hogy az elágazások feltételei közül egy sem igaz – ilyenkor <strong>semelyik ág nem</strong> fog végrehajtódni.</p><h3 id="osszetett-elagazas" tabindex="-1"><a class="header-anchor" href="#osszetett-elagazas" aria-hidden="true">#</a> Összetett elágazás</h3><p><strong>Összetett elágazás</strong>nak nevezzük a több végrehajtási ággal rendelkező elágazást. Az összetett elágazást az különbözteti meg az egyszerű elágazások egymásba ágyazásával nyert, szintén több végrehajtási ággal rendelkező szerkezettől, hogy itt egyetlen kifejezés kerül kiértékelésre, melynek eredménye alapján kerül az egyes ágakra a vezérlés.</p><p>Az <strong>összetett elágazás</strong>ok képzéséhez a switch kulcsszó áll a rendelkezésünkre, amely azonban – más nyelvbeli előfordulásával ellentétben – igen korlátozott a Javában. A kiértékelendő kifejezés értéke ugyanis csak megszámlálható típusú (szám vagy karakter) lehet.<br> Az összetett elágazás szintaktikája a következő:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">switch</span> <span class="token punctuation">(</span>kifejezes<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
    <span class="token keyword">case</span> cimke1<span class="token operator">:</span>
        utasitasok1<span class="token punctuation">;</span>
    <span class="token keyword">break</span><span class="token punctuation">;</span> 
    <span class="token keyword">case</span> cimke2<span class="token operator">:</span> 
    <span class="token keyword">case</span> cimke3<span class="token operator">:</span>
        utasitasok2<span class="token punctuation">;</span>
    <span class="token keyword">break</span><span class="token punctuation">;</span> 
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
    <span class="token keyword">default</span><span class="token operator">:</span> 
        utasitasok3<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A <strong>switch</strong> fejében megadott kifejezés értékelődik ki először, és azon ág kerül majd végrehajtásra, amelyhez tartozó címke megegyezik a kifejezés értékével.</p><div class="hint-container danger"><p class="hint-container-title">FONTOS</p><p>Ha nem írjuk ki az egyes ágak végére a <strong>break</strong> utasítást, a végrehajtás a következő ágon folytatódik. A <strong>break</strong> hatására azonban kiugrunk az elágazás blokkjából, és az utána szereplő első utasításra kerül a vezérlés.</p></div><p>Az újabb címke nem szakítja meg tehát a végrehajtást. A fenti példában például a 2-essel és 3-assal jelzett címkék esetén is az <strong>utasítások2</strong> kerül majd végrehajtásra.</p><p>A <strong>default</strong> ágban adhatjuk meg azt az utasítást vagy blokkot, amely akkor kerül végrehajtásra, ha a kifejezés egyik megadott címkeértékkel sem egyezik meg. Ezen ág megadása nem kötelező. Az összetett elágazást a kulcsszavak megfelelő tagolásával, és nem a blokkok elejét és végét jelző kapcsos zárójelek kiírásával tesszük olvashatóvá.<br> Nézzünk egy példát összetett elágazásra:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">switch</span> <span class="token punctuation">(</span>szam<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
    <span class="token keyword">case</span> <span class="token number">0</span><span class="token operator">:</span>
        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Nulla&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// szam == 0</span>
    <span class="token keyword">break</span><span class="token punctuation">;</span> 
    <span class="token keyword">case</span> <span class="token number">1</span><span class="token operator">:</span>
        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Egesz pici szam&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// szam == 1 </span>
    <span class="token keyword">case</span> <span class="token number">2</span><span class="token operator">:</span>
        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Egy vagy ketto&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// szam == 1,2</span>
    <span class="token keyword">break</span><span class="token punctuation">;</span> 
    <span class="token keyword">default</span><span class="token operator">:</span>
        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Legalabb harom&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// szam == 3,4,5... </span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A <strong>switch</strong> elágazás különlegességét az adja, hogy a <strong>break</strong> utasítással mi magunk szabályozhatjuk az ágak egymás utáni kiértékelésének módját és sorrendjét. Ha azonban minden ág végére kitesszük a blokkból kiugró utasítást, úgy az elágazás könnyedén átírható egymásba ágyazott egyszerű elágazásokból képzett szerkezetre.</p><h2 id="ciklus-tipusai-alkalmazasa" tabindex="-1"><a class="header-anchor" href="#ciklus-tipusai-alkalmazasa" aria-hidden="true">#</a> Ciklus típusai, alkalmazása</h2><p>A szekvencia és elágazás mellett olyan programozási struktúrára is szükségünk lesz, amely egy adott utasítást vagy azokból képzett blokkot többször végrehajt egymás után – ezt nevezzük ciklusnak. Az egymás után többször végrehajtandó utasítás vagy blokk a ciklusmag. A ciklusmag végrehajtása, illetve annak befejezése függhet egy feltétel kiértékelésétől, de az ismétlések számát is meghatározhatjuk.</p><div class="hint-container tip"><p class="hint-container-title">FONTOS</p><p>A szekvencián, elágazáson és cikluson kívül nincs szükség más vezérlési szerkezetekre programjaink megírásához.</p></div><h3 id="eloltesztelo-ciklus" tabindex="-1"><a class="header-anchor" href="#eloltesztelo-ciklus" aria-hidden="true">#</a> Elöltesztelő ciklus</h3><p>Elöltesztelő ciklusnak nevezzük azt a ciklust, melyben a ciklusmag addig hajtódik végre, ameddig a ciklusfeltétel teljesül. Ha a ciklusfeltétel sosem teljesül, a vezérlés sosem kerül rá a ciklusmag utasításaira.<br> Az elöltesztelő ciklus formája a következő:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">while</span> <span class="token punctuation">(</span>feltetel<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
    <span class="token comment">// Ciklusmag</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ha a ciklusmag egyetlen utasításból áll, a blokkot jelző kapcsos zárójelek kiírása nem lenne kötelező, a jobb olvashatóság miatt azt mégis mindig kitesszük. Pontosvesszővel csak a ciklusmagban szereplő utasításokat kell lezárnunk. Nézzük meg, hogyan írhatjuk ki elöltesztelő ciklussal a számokat 1-től 10-ig a képernyőre!</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>

<span class="token keyword">while</span> <span class="token punctuation">(</span>i <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    i<span class="token operator">+=</span><span class="token number">1</span><span class="token punctuation">;</span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A fenti megoldás a klasszikus megoldáshoz hasonlít. Prefix operátorral azonban tovább egyszerűsíthetjük.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>

<span class="token keyword">while</span> <span class="token punctuation">(</span>i <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token operator">++</span>i<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="hatultesztelo-ciklus" tabindex="-1"><a class="header-anchor" href="#hatultesztelo-ciklus" aria-hidden="true">#</a> Hátultesztelő ciklus</h3><p>A hátultesztelő ciklus esetén a ciklus szintén addig fut, míg a megadott feltétel teljesül – ám a feltétel kiértékelése a ciklusmag végrehajtása után következik. Így a ciklusmag legalább egyszer lefut. A hátultesztelő ciklus formája a következő:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">do</span> <span class="token punctuation">{</span>
    <span class="token comment">// ciklusmag</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token punctuation">}</span> <span class="token keyword">while</span><span class="token punctuation">(</span>feltetel<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ha a ciklusmag egyetlen utasításból áll, a blokkot jelző kapcsos zárójelek kiírása nem lenne kötelező, a jobb olvashatóság miatt azt mégis mindig kitesszük. A ciklust lezáró feltétel után a pontosvesszőt ki kell tennünk! Most nézzük meg, hogyan írhatók ki a számok 1-től 10-ig hátultesztelő ciklussal!</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>

<span class="token keyword">do</span> <span class="token punctuation">{</span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token operator">++</span>i<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span> <span class="token keyword">while</span> <span class="token punctuation">(</span>i <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Amennyiben a prefix értéknövelést postfixszé változtatjuk, módosítanunk kell a ciklusfeltételt is.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token keyword">do</span> <span class="token punctuation">{</span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>i<span class="token operator">++</span><span class="token punctuation">)</span><span class="token punctuation">;</span> 
<span class="token punctuation">}</span> <span class="token keyword">while</span> <span class="token punctuation">(</span>i <span class="token operator">&lt;=</span> <span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Mivel itt a szám kiírása után kapja meg az i a következő értéket, a ciklusfeltételben azt is engednünk kell, hogy 10-es érték esetén még egyszer belépjünk a ciklusmagba.</p><h3 id="for-ciklus" tabindex="-1"><a class="header-anchor" href="#for-ciklus" aria-hidden="true">#</a> For-ciklus</h3><p>Egy harmadik típusú ciklust, az ún. <strong>for-ciklus</strong>t, mellyel nagyon egyszerűen írhatunk számlálót léptető ciklusokat. A for-ciklus esetén annak fejében van lehetőségünk a számlálóváltozó deklarálására, értékének növelésére, illetve a ciklusfeltétel megadására.</p><p>A for-ciklus formája a következő:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">for</span> <span class="token punctuation">(</span>utasitas1<span class="token punctuation">;</span> feltetel<span class="token punctuation">;</span> utasitas2<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// Ciklusmag</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A for-ciklus valójában minden esetben átírható egy vele ekvivalens elöltesztelő ciklussá.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code>utasitas1<span class="token punctuation">;</span>
<span class="token keyword">while</span> <span class="token punctuation">(</span>feltetel<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// Ciklusmag</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
    utasitas2<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A for-ciklus esetén is mindig kitesszük a ciklusmag elejét és végét jelző kapcsos zárójeleket! Nézzük meg, hogyan írható szokásos példánk (számok kiírása 1-től 10-ig) for-ciklussal!</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> 
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container danger"><p class="hint-container-title">FONTOS</p><p>A for-ciklus fejében deklarált változó csak a ciklusmagban érvényes, a ciklus után már nem használható.</p></div><div class="hint-container tip"><p class="hint-container-title">Tips</p><p>Ciklusok írásánál, különösképpen azok egymásba ágyazásánál ügyeljünk a kód tagolására! A ciklus feje és a ciklusmagot lezáró kapcsos zárójel kerüljön mindig egy vonalba, a ciklusmag utasításait kezdjük beljebb, azonos oszlopban.</p></div><h2 id="kivetelkezeles" tabindex="-1"><a class="header-anchor" href="#kivetelkezeles" aria-hidden="true">#</a> Kivételkezelés</h2><h3 id="hiba-biztonsagos-program" tabindex="-1"><a class="header-anchor" href="#hiba-biztonsagos-program" aria-hidden="true">#</a> Hiba, biztonságos program</h3><p>A programhibák két fő csoportját szokás megkülönböztetni. <strong>Szintaktikai hibának</strong> nevezzük azon programhibákat, melyek esetén az általunk írt program valamely része nem felel meg a nyelv szabályainak, azaz szintaktikájának.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code>imt i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
system<span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;alma&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">for</span><span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">,</span> i<span class="token operator">&lt;=</span> <span class="token number">10</span><span class="token punctuation">,</span> i<span class="token operator">++</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az első példában kulcsszó elgépelését láthatjuk. A második példa azért fog szintaktikai hibát adni, mivel a Java megkülönbözteti a kis és nagybetűket, a System osztály azonosítója pedig nagy kezdőbetűvel írandó. A harmadik esetben pedig a for-ciklus fejében pontosvessző helyett vesszővel választottuk el a ciklusfej részeit.</p><p>Szemantikai hibának nevezzük azon kódrészleteket, melyek bár megfelelnek a nyelv szabályainak, mégsem értelmezhetők avagy nem adnak jó megoldást. Példák szemantikai hibákra:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> a<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> b<span class="token operator">=</span><span class="token number">10</span><span class="token operator">/</span>a<span class="token punctuation">;</span>
x1<span class="token operator">=</span><span class="token punctuation">(</span><span class="token operator">-</span>b<span class="token operator">+</span><span class="token class-name">Math</span><span class="token punctuation">.</span><span class="token function">sqrt</span><span class="token punctuation">(</span>b<span class="token operator">*</span>b<span class="token operator">-</span><span class="token number">4</span><span class="token operator">*</span>a<span class="token operator">*</span>c<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token operator">/</span><span class="token number">2</span><span class="token operator">*</span>a<span class="token punctuation">;</span>
args<span class="token punctuation">[</span><span class="token operator">++</span>i<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az első példában egyértelmű a szemantikai hiba: nullával osztani Javában sem lehet. A másik két példa azonban nem okoz minden esetben hibát megfelelő diszkriminánsból vonhatunk gyököt, ahogy ha van még feldolgozatlan paraméterünk, a megnövelt indexszel hozzáférhetünk. Azonban a kifejezésekben szereplő együtthatók bizonyos értékeinél hibás működés áll elő – a Java pedig ilyen esetben is megkövetelheti az esetleg előforduló hibák kezelését.</p><p>A Java nyelv megírásánál ugyanis elsődleges szempont volt a nyelv biztonságossága. Egy biztonságos program szemantikai hibáknál nem áll meg, hanem megpróbálja kezelni azokat a belőlük következő hibákkal együtt. A Java nyelv a kivételkezeléssel biztosítja számunkra biztonságos programok írásának lehetőségét.</p><h2 id="kivetel" tabindex="-1"><a class="header-anchor" href="#kivetel" aria-hidden="true">#</a> Kivétel</h2><h3 id="a-kivetelek-kezelese" tabindex="-1"><a class="header-anchor" href="#a-kivetelek-kezelese" aria-hidden="true">#</a> A kivételek kezelése</h3><p>A program futása során bekövetkező hibát a Java <strong>exceptionnek</strong>, magyarul <strong>kivételnek</strong> nevezi. Ez egy olyan – kivételes – eseményt jelent, amely megszakítja az utasítások végrehajtásának normális menetét. Ezért a program futása kivételes módon folyik tovább – ezt valósítja meg a kivételkezelés.</p><p>Amikor hiba keletkezik, automatikusan létrejön egy <strong>kivételobjektum</strong>.<br> Ezen kivételobjektum addig él, míg nem kezeljük azt – a kezelés után pedig automatikusan megszűnik. A <strong>kivétel kiváltódásának</strong> nevezzük azt, amikor a hiba hatására létrejön az objektum. Kivételt kiválthat egy hibás művelet, egy előre megírt Java csomag vagy osztály, de a programozó maga is definiálhat és kiválthat saját kivételeket.</p><p>Amikor az adott kivételről értesülünk, lehetőségünk van az adott <strong>kivétel elkapására</strong>. A kivételt azon blokk végén szokták elkapni, amelyben kiváltódtak. A <strong>kivétel kezelésének</strong> nevezzük azt a programrészletet, melyben az adott hibát orvosoljuk.</p><table><thead><tr><th><strong>Kivételosztály</strong></th><th><strong>Leírása</strong></th></tr></thead><tbody><tr><td><strong>IOException</strong></td><td>Ki és bemeneti hibák esetén váltódik ki, pl. konzolról való beolvasáskor.</td></tr><tr><td><strong>FileNotFoundException</strong></td><td>Az IOException egyik alkivételosztálya. Akkor kapjuk például, ha nem létező fájlba próbálunk írni.</td></tr><tr><td><strong>EOFException</strong></td><td>Fájl végét jelző kivétel. Szintén az IOException alosztálya.</td></tr></tbody></table><p>A Java nyelvben azon kivételeket, melyek kezelése minden esetben kötelező, ellenőrzött kivételeknek nevezzük. Az ellenőrzött kivételek nem kezelése szintaktikai hibát eredményez, és a program fordítása sikertelen lesz.</p><p>Azon kivételeket, melyek kezelése nem kötelező, <strong>nem ellenőrzött kivételeknek</strong> nevezzük. Ezek kiváltódásának ellenőrzése nem kötelező, ám minden esetben ajánlott.<br> Vegyünk sorra néhány gyakori nem ellenőrzött kivételt:</p><table><thead><tr><th><strong>Kivételosztály</strong></th><th><strong>Leírása</strong></th></tr></thead><tbody><tr><td><strong>RuntimeException</strong></td><td>valamennyi futásidejű kivétel ősosztálya.</td></tr><tr><td><strong>NullPointerException</strong></td><td>Olyan esetben kapjuk, ha null értékű, azaz inicializálatlan változóra vagy objektumra hivatkozunk.</td></tr><tr><td><strong>IndexOutOfBoundsException</strong></td><td>Túlindexelést jelző kivétel. Akkor kapjuk, ha egy tömb, karakterlánc vagy más indexelhető szerkezet nem létező indexére hivatkozunk.</td></tr><tr><td><strong>ArithmeticException</strong></td><td>Aritmetikai műveletek hibájakor kapjuk, például nullával való osztáskor.</td></tr><tr><td><strong>NumberFormatException</strong></td><td>Akkor kapjuk például, ha nem megfelelő számot tartalmazó karakterláncot próbálunk szám típusúvá konvertálni.</td></tr><tr><td><strong>IllegalArgumentException</strong></td><td>Akkor váltódik ki, ha egy metódust nem megfelelő paraméterekkel hívunk.</td></tr></tbody></table><p>Ha a kivételt nem kezeljük abban a blokkban, ahol keletkezett, úgy a tartalmazó blokknak adódik át. Ez egészen addig folytatódik, míg valahol nincs egy olyan kivételkezelő blokk, mely az adott kivételt kezelné. Ha a kivételt egyik blokkban sem kezeljük, és feljut a legfelsőbb szintre: a program <strong>terminál</strong>.</p><p>Azon műveleteket, melyek kivételt dobhatnak try-blokkba kell szerveznünk, melynek végén kezeljük az adott blokkban keletkezhető kivételeket.<br> A kivételkezelés szintaktikája:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">try</span> <span class="token punctuation">{</span>
    <span class="token comment">//kritikus műveletek;</span>
<span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">KivetelTipus1</span> e1<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
    <span class="token comment">//hibakezelés</span>
<span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">KivetelTipus2</span> e2<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">//hibakezelés</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A következő példa olyan kódrészletet tartalmaz, amely kivételt dobhat.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Osztas</span> <span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token keyword">int</span> szam <span class="token operator">=</span> <span class="token class-name">Integer</span><span class="token punctuation">.</span><span class="token function">parseInt</span><span class="token punctuation">(</span>args<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">int</span> eredmeny <span class="token operator">=</span> <span class="token number">1</span><span class="token operator">/</span>szam<span class="token punctuation">;</span>
        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">print</span><span class="token punctuation">(</span><span class="token string">&quot;A szám reciproka: &quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">print</span><span class="token punctuation">(</span>eredmeny<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> 
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az egyik lehetséges hibaforrás a felhasználó által adott paraméter számmá alakítása, hiszen ha az karakteres típusú érték vagy a szám az ezreseknél szóközzel tagolt úgy a számmá alakítás nem fog sikerülni. Ilyenkor <code>NumberFormatException</code> fog dobódni. hasonló veszélyt rejt a számmal való osztás, hiszen ha a szám nulla, úgy az osztás <code>ArithmeticException</code> kivételt fog dobni.</p><p>A fenti példa biztonságos változata a következő:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Osztas</span> <span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token keyword">try</span> <span class="token punctuation">{</span>
            <span class="token keyword">int</span> szam <span class="token operator">=</span> <span class="token class-name">Integer</span><span class="token punctuation">.</span><span class="token function">parseInt</span><span class="token punctuation">(</span>args<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span> 
            <span class="token keyword">int</span> eredmeny <span class="token operator">=</span> <span class="token number">1</span><span class="token operator">/</span>szam<span class="token punctuation">;</span> 
            <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">print</span><span class="token punctuation">(</span><span class="token string">&quot;A szam reciproka: &quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">print</span><span class="token punctuation">(</span>eredmeny<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">NumberFormatException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
            <span class="token class-name">System</span><span class="token punctuation">.</span>err<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Hibas szamformatum!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">ArithmeticException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
            <span class="token class-name">System</span><span class="token punctuation">.</span>err<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Osztasi hiba!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span> 
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ha a paraméterként megadott értéket nem lehet számmá konvertálni, a vezérlés a <code>NumberFormatException</code> kivételt kezelő ágra ugrik, majd a program futása befejeződik. Így az osztás művelete nem hajtódik végre, és nem is írjuk ki az eredményt. Ha az osztás közben kapjuk a kivételt, a konzolra való írás helyett az <code>ArithmeticExceptiont</code> elkapó ágba lépünk, majd a program végrehajtása befejeződik, mivel a kivételkezelő blokk után nincs utasítás.</p><div class="hint-container tip"><p class="hint-container-title">FONTOS</p><p>Ha kivétel keletkezik, a program vezérlése az adott blokkhoz tartozó kivételkezelő részre ugrik, és a kivétel kezelése után sem tér vissza a kivételt kiváltó utasításra. A kivétel keletkezése után a vezérlés abban a blokkban folytatódik, ahol a kivételt sikeresen kezeltük, mégpedig a kivételkezelő részt követő első utasítással.</p></div><p>A <code>finally</code> ág segítségével pedig olyan kódrészletet is írhatunk, amely normál programműködés és kivétel keletkezése esetén is mindenképpen lefut. Ez a blokk akkor is végrehajtódik, amennyiben a kapott kivételt az adott blokkban nem kezeljük, azaz nem írtunk hozzá catch-ágat. Ilyenkor a finally ág lefutása után a kivétel a tartalmazó blokknak adódik tovább.</p><p>A <code>finally</code> ág a try-catch blokkban a kivételek kezelése után következik.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">try</span> <span class="token punctuation">{</span>
    <span class="token comment">//kritikus műveletek</span>
<span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">KivetelTipus1</span> e1<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">//hibakezelés</span>
<span class="token punctuation">}</span> 
<span class="token keyword">finally</span> <span class="token punctuation">{</span>
   <span class="token comment">//befejező műveletek</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A finally ágban általában a kritikus műveletekhez szükséges erőforrások felszabadítását, az ott megnyitott fájlok bezárását szokás megvalósítani – azaz minden olyan műveletet, amelyet kivétel keletkezése esetén is végre szeretnénk hajtatni.</p><h2 id="egy-es-tobbdimenzios-tombok-definialasa-es-alkalmazasa" tabindex="-1"><a class="header-anchor" href="#egy-es-tobbdimenzios-tombok-definialasa-es-alkalmazasa" aria-hidden="true">#</a> Egy- és többdimenziós tömbök definiálása és alkalmazása</h2><h3 id="egydimenzios-tombok" tabindex="-1"><a class="header-anchor" href="#egydimenzios-tombok" aria-hidden="true">#</a> Egydimenziós tömbök</h3><p>A <strong>tömb</strong> egy olyan összetett adattípus, amely meghatározott alaptípusú változókat fog össze oly módon, hogy azokra indexszel hivatkozhatunk. A tömb létrehozásakor meg kell határoznunk annak dimenzióját – ettől függően az egyes elemekre egy vagy több indexszámmal hivatkozhatunk. Az egydimenziós tömböt <strong>vektornak</strong>, a többdimenziós tömböt <strong>mátrixnak</strong> is szokás nevezni.</p><p>Mint minden egyéb, a Javában a tömb is egy objektum. Ezért a tömb változóknak számos metódusát használhatjuk majd kezelésükhöz. A szögletes zárójelek (<strong>[]</strong>) segítségével definiálhatunk <strong>egydimenziós tömböt</strong>. Tömb definiálásakor meg kell határozunk a tömb elemeinek típusát és a tömb azonosítóját. Hasonlóan egyszerű típusú változók definíciójához egy utasításban több tömböt és létrehozhatunk.</p><p>A szögletes zárójelet írhatjuk az alaptípus vagy a tömbváltozó azonosítója után.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span><span class="token punctuation">[</span><span class="token punctuation">]</span> v<span class="token punctuation">,</span> w<span class="token punctuation">;</span> <span class="token comment">// v es w egydimenzios tombok</span>
<span class="token keyword">int</span> x<span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span> y<span class="token punctuation">;</span> <span class="token comment">// x integervektor, y integer tipusu szam</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>A fenti példában csak definiáltuk a tömb típusú változóinkat, de a hosszuk egyelőre 0, melyet <strong>üres tömbnek</strong> szokás hívni. A tömb hosszát egy speciális értékadó utasítással adhatjuk meg, hosszát pedig a <strong>length</strong> tulajdonság segítségével kérdezhetjük le.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span><span class="token punctuation">[</span><span class="token punctuation">]</span> v<span class="token punctuation">;</span> <span class="token comment">// v vektor</span>
v <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token keyword">int</span><span class="token punctuation">[</span><span class="token number">20</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token comment">// v vektor 20 elemet tartalmazhat</span>
<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">print</span><span class="token punctuation">(</span><span class="token string">&quot;Tomb hossza: &quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">print</span><span class="token punctuation">(</span>v<span class="token punctuation">.</span>length<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// v vektor hossza</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container warning"><p class="hint-container-title">FONTOS</p><p>A Java a tömb elemeit 0-tól indexeli, így az első elem indexe 0, az utolsó elemé pedig hossz-1, azaz tömb.length-1.</p></div><p>Ha tehát egy ciklusban kívánjuk feldolgozni egy tömb elemeit, azt a következőképpen tehetjük meg:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> v<span class="token punctuation">.</span>length<span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    v<span class="token punctuation">[</span>i<span class="token punctuation">]</span> <span class="token operator">=</span> i<span class="token punctuation">;</span> <span class="token comment">// minden vektorelem erteke az indexe lesz</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ha egy tömbben érvénytelen indexre hivatkozunk (pl. v[-2], v[v.length] stb.), akkor <strong>IndexOutOfBoundsException</strong> nevű kivétel keletkezik. Ennek kezelése csak abban az esetben szükséges, ha nem vagyunk biztosak a vektor elemeinek számában vagy a hivatkozott elem létezésében. A tömbindexek megfontolt kezelése esetén ez a kivétel elkerülhető.</p><p>Ha futás közben mégis ezt a kivételt kapjuk, akkor ellenőrizzük a kód azon részeit, ahol a tömb elemeire hivatkozunk. Az eddigiekhez hasonlóan a tömb definiálásakor is adhatunk neki kezdőértéket. Ekkor a tömb hossza az inicializáló értékadásban megadott elemek számával fog megegyezni.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span><span class="token punctuation">[</span><span class="token punctuation">]</span> primszamok <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">,</span> <span class="token number">7</span><span class="token punctuation">,</span> <span class="token number">11</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token keyword">char</span><span class="token punctuation">[</span><span class="token punctuation">]</span> abc <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token char">&#39;a&#39;</span><span class="token punctuation">,</span> <span class="token char">&#39;b&#39;</span><span class="token punctuation">,</span> <span class="token char">&#39;c&#39;</span><span class="token punctuation">,</span> <span class="token char">&#39;d&#39;</span><span class="token punctuation">,</span> <span class="token char">&#39;e&#39;</span><span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>A program paraméteres kezelésénél használt <strong>String[] args</strong> tulajdonképpen egy karakterlánc típusú változókból álló, tetszőleges hosszúságú tömb.</p><div class="hint-container tip"><p class="hint-container-title">FONTOS</p><p>Bár a tömb összetett adattípus, a tömb változójának azonosítóját is kisbetűvel szokás kezdeni.</p></div><h3 id="tobbdimenzios-tombok" tabindex="-1"><a class="header-anchor" href="#tobbdimenzios-tombok" aria-hidden="true">#</a> Többdimenziós tömbök</h3><p>Amennyiben több kapcsos zárójelet írunk a tömb definiálásánál, <strong>többdimenziós tömböt</strong> kapunk. Így valójában vektorokból álló vektort hozunk létre. A kapcsos zárójelpárok száma adja a tömb dimenzióját.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span><span class="token punctuation">[</span><span class="token punctuation">]</span> v<span class="token punctuation">,</span> w<span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token comment">// v egydimenzios, w ketdimenzios tomb int[][] y; // y ketdimenzios tomb</span>
<span class="token keyword">int</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token punctuation">]</span> x<span class="token punctuation">;</span> <span class="token comment">// x haromdimenzios tomb</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>A többdimenziós mátrixokat is inicializálhatom, az egyes sorok száma és hossza a megadott értékeknek megfelelő lesz.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token punctuation">]</span> y <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">{</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">,</span> <span class="token number">6</span> <span class="token punctuation">}</span><span class="token punctuation">}</span><span class="token punctuation">;</span> <span class="token comment">// y 2x3-as tomb</span>
<span class="token keyword">char</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token punctuation">]</span> ch <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">{</span> <span class="token char">&#39;a&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token char">&#39;b&#39;</span><span class="token punctuation">,</span> <span class="token char">&#39;c&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">}</span><span class="token punctuation">;</span> <span class="token comment">// szabalytalan tomb</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Az egydimenziós tömbhöz hasonlóan meghatározhatom az egyes dimenziók fix méretét – így az egyes sorok és oszlopok száma azonos lesz, azaz <strong>szabályos mátrixot</strong> kapunk. Mivel azonban az egyes vektorelemek által tartalmazott vektorok méretét külön-külön is megadhatom, <strong>változó méretű tömböket</strong> (pl. kesztyűmátrixot) is létrehozhatok....</p><p>A következő példában definiálunk egy szabályos mátrixot és egy kesztyűmátrixot, melyet fel is töltünk számokkal:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token punctuation">]</span> tomb1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token keyword">int</span><span class="token punctuation">[</span><span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token comment">// 3x4-es szabalyos matrix </span>
<span class="token keyword">int</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token punctuation">]</span> tomb2 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token keyword">int</span> <span class="token punctuation">[</span><span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token comment">// 3 elemu , tombokbol allo tomb</span>

<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> tomb2<span class="token punctuation">.</span>length<span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> 
    tomb2<span class="token punctuation">[</span>i<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token keyword">int</span><span class="token punctuation">[</span>i <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> j <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> j <span class="token operator">&lt;</span> tomb2<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">.</span>length<span class="token punctuation">;</span> j<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        tomb2<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token operator">=</span> i <span class="token operator">+</span> j <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">;</span> 
        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">print</span><span class="token punctuation">(</span>tomb2<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token operator">+</span> <span class="token string">&quot; &quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="tipusosztalyok" tabindex="-1"><a class="header-anchor" href="#tipusosztalyok" aria-hidden="true">#</a> Típusosztályok</h2><h3 id="csomagoloosztaly" tabindex="-1"><a class="header-anchor" href="#csomagoloosztaly" aria-hidden="true">#</a> Csomagolóosztály</h3><p>A <strong>típusosztály</strong> olyan Java osztály, melynek egyetlen adattulajdonsága van az adat tárolására, és melynek metódusai az adott típuson elvégezhető típusműveletek. Egy típusosztályhoz létrehozott példány pedig az adott típusú változónak megfelelő, ám azzal nem egyenlő objektum. Javában minden elemi típusnak van egy <strong>csomagolóosztálya</strong> azaz egy olyan típusosztály, amely az adott alaptípusnak felel meg. Ennek azonosítója általában a típus nagybetűs változata (<strong>Javában az osztályokat nagy kezdőbetűvel szokás elnevezni</strong>), de néhány esetben az adott rövidítéshez tartozó teljes kifejezés.</p><p>A <strong>void</strong> a Javában a típus nélküliséget jelző kulcsszó. Ezzel a kulcsszóval jelezzük például, ha egy metódus nem tér vissza semmilyen értékkel. A <strong>void</strong> kulcsszónak megfelelő csomagolóosztály a <strong>Void</strong>, amely nem példányosítható.</p><table><thead><tr><th><strong>Alaptípus</strong></th><th><strong>Csomagolóosztály</strong></th></tr></thead><tbody><tr><td>byte</td><td><strong>Byte</strong></td></tr><tr><td>short</td><td><strong>Short</strong></td></tr><tr><td>int</td><td><strong>Integer</strong></td></tr><tr><td>long</td><td><strong>Long</strong></td></tr><tr><td>float</td><td><strong>Float</strong></td></tr><tr><td>double</td><td><strong>Double</strong></td></tr><tr><td>char</td><td><strong>Character</strong></td></tr><tr><td>boolean</td><td><strong>Boolean</strong></td></tr><tr><td>void</td><td><strong>Void</strong></td></tr></tbody></table><p>Amennyiben egy adattal csak egyszerű műveleteket kívánunk elvégezni, úgy nem szükséges a típusosztály használata – elegendő magát az alaptípust használnunk. Ha azonban szükségünk van a típusosztály nyújtotta műveletekre, netán objektumként kell az adatra hivatkoznunk – úgy használjuk a csomagolóosztályokat.<br> Javában a <strong>karakterláncot</strong> nem tudjuk elemi adattípussal megvalósítani, csak típusosztállyal. A sztringek kezelésére a <strong>String</strong> típusosztály áll a rendelkezésünkre.</p><h3 id="konstruktor-es-inicializalas" tabindex="-1"><a class="header-anchor" href="#konstruktor-es-inicializalas" aria-hidden="true">#</a> Konstruktor és inicializálás</h3><p>Ha egy típusosztályból kívánunk létrehozni egy példányt, meg kell hívnunk annak konstruktorát. A konstruktorok általában inicializálnak is; paraméterként adhatjuk meg a változó kezdőértékét.</p><div class="hint-container tip"><p class="hint-container-title">FONTOS</p><p>A típusobjektumok esetén a konstruktorral inicializálás kötelező, mivel ezen objektumok értéke nem módosítható.</p></div><p>Nézzünk példát inicializáló konstruktorhívásra:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">Integer</span> ii <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Integer</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// kezdoerteke 3</span>
<span class="token class-name">String</span> s <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">String</span><span class="token punctuation">(</span><span class="token string">&quot;123&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// kezdoerteke &quot;123&quot;</span>
<span class="token class-name">Integer</span> ij <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Integer</span><span class="token punctuation">(</span>s<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// kezdoerteke: 123</span>
<span class="token class-name">Character</span> cd <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Character</span><span class="token punctuation">(</span><span class="token char">&#39;a&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// kezdoerteke: a</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Mint azt a fenti példában láthatjuk, egy típusosztály több konstruktorral is rendelkezhet. Az <strong>Integer</strong> típusú változót létrehozásakor inicializálhatjuk szám és karakterlánc típusú értékkel is; ez utóbbi esetben azonban kezelnünk kell az esetleg kiváltódó <strong>NumberFormatException</strong> kivételt.</p><h3 id="tipuskonverzio" tabindex="-1"><a class="header-anchor" href="#tipuskonverzio" aria-hidden="true">#</a> Típuskonverzió</h3><p>A típusosztályok segítségével <strong>típuskonverziót</strong> is végezhetünk, azaz egy adott értéket konvertálhatunk valamilyen más típusúvá. Ilyenkor hivatkozhatunk a típusosztályból példányosított változó metódusára, de a típusosztály metódusaként is hívhatjuk.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token class-name">Integer</span><span class="token punctuation">.</span><span class="token function">parseInt</span><span class="token punctuation">(</span><span class="token string">&quot;123&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// tipusosztaly metodusakent</span>
<span class="token keyword">int</span> par1 <span class="token operator">=</span> <span class="token class-name">Integer</span><span class="token punctuation">.</span><span class="token function">parseInt</span><span class="token punctuation">(</span>args<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// tipusosztaly metodusakent</span>
<span class="token class-name">Integer</span> ii <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Integer</span> <span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">String</span> s <span class="token operator">=</span> ii<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ii objektum metodusakent</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az egyes típusobjektumok értékeit pedig más típusúként is lekérdezhetjük:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">Integer</span> ii <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Integer</span> <span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">byte</span> b <span class="token operator">=</span> ii<span class="token punctuation">.</span><span class="token function">byteValue</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// erteke: 100</span>
<span class="token keyword">float</span> f <span class="token operator">=</span> ii<span class="token punctuation">.</span><span class="token function">floatValue</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// erteke: 100.0 lebegopontos szam</span>
<span class="token keyword">int</span> i <span class="token operator">=</span> ii<span class="token punctuation">.</span><span class="token function">intValue</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="osztalyok-objektumok-definialasa-es-alkalmazasa" tabindex="-1"><a class="header-anchor" href="#osztalyok-objektumok-definialasa-es-alkalmazasa" aria-hidden="true">#</a> Osztályok, objektumok definiálása és alkalmazása</h2><h3 id="osztalyok-definialasa-objektumok" tabindex="-1"><a class="header-anchor" href="#osztalyok-definialasa-objektumok" aria-hidden="true">#</a> Osztályok definiálása, objektumok</h3><p>Az <strong>osztály</strong> azonos jellegű dolgok (pl. emberek, tárgyak, adatszerkezetek) modelljét leíró önálló egység. Az osztályokból <strong>példányokat</strong> hozunk létre, melyeket <strong>objektumoknak</strong> is nevezünk – ezt nevezzük <strong>példányosításnak</strong>.</p><p>Az osztályok definíciója Javában két részből áll: meg kell határoznunk az osztály példányainak állapotát leíró <strong>változókat</strong> (más néven <strong>tulajdonságokat</strong>), illetve definiálnunk kell az osztály viselkedését, műveleteit meghatározó <strong>metódusokat</strong>.</p><p>Javában egy osztályt a class kulcsszóval kezdődő szerkezettel definiálhatunk. Az alábbi példában létrehozunk egy Tanulo osztályt, melynek három tulajdonsága lesz: a tanuló neve, évfolyamának száma (pl. 13) és az osztály betűjele (pl. &#39;B&#39;). Definiálunk egy metódust is, mellyel léptethetjük a tanuló aktuális évfolyamának számát év végén.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">class</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span> 
    <span class="token class-name">String</span> nev<span class="token punctuation">;</span>
    <span class="token keyword">int</span> evfolyam<span class="token punctuation">;</span> 
    <span class="token keyword">char</span> osztaly<span class="token punctuation">;</span>

    <span class="token keyword">void</span> <span class="token function">evfolyamotLep</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        evfolyam <span class="token operator">+=</span> <span class="token number">1</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az <code>evfolyamotLep</code> metódusnak <code>void</code> a típusa, mivel nincs visszatérési értéke, és bemenő paramétere sincs, mivel értelemszerűen eggyel növeli az évfolyam aktuális értékét.</p><div class="hint-container warning"><p class="hint-container-title">FONTOS</p><p>Egy Java fájlban több osztályt is definiálhatunk, de ha másik Java fájlban is el szeretnénk azt érni, akkor csak egyet tartalmazhat, melynek neve meg kell, hogy egyezzen az őt tartalmazó fájl nevével.</p></div><p>Amikor létrehozunk egy Java projektet, mindig létrejön egy Main osztály, és <code>Main.java</code> lesz az őt tartalmazó fájl neve is.</p><div class="hint-container danger"><p class="hint-container-title">FONTOS</p><p>Az osztályok azonosítóit nagybetűvel szokás kezdeni. Amennyiben összetett kifejezés szerepel benne, úgy minden egyes új szót is nagybetűvel írunk (pl. EgyetemiHallgato). A tulajdonságok és metódusok neveit kisbetűvel szokás kezdeni.</p></div><p>A <code>class</code> kulcsszó előtt <strong>módosítót</strong> is megadhatunk, mely az osztály láthatóságát vagy viselkedését befolyásolja. Ha az osztálydefiníciót a <code>public</code> módosítóval kezdjük, úgy az osztály másik csomagban, fájlban is látható lesz, enélkül az osztályt csak az adott csomagban használhatjuk. Az alábbi példában nézzük meg, hogyan példányosíthatjuk a fent definiált osztályt, és hogyan hivatkozhatunk a tulajdonságaira és metódusaira.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">Tanulo</span> tan1<span class="token punctuation">;</span> <span class="token comment">// objektumvaltozo definialasa</span>
tan1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Tanulo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// objektum letrehozasa , peldanyositas</span>
tan1<span class="token punctuation">.</span>nev <span class="token operator">=</span> <span class="token string">&quot;Nagy Lajos&quot;</span><span class="token punctuation">;</span> <span class="token comment">// nev tulajdonsag inicializalas</span>
tan1<span class="token punctuation">.</span>evfolyam <span class="token operator">=</span> <span class="token number">13</span><span class="token punctuation">;</span> <span class="token comment">// evfolyam tulajdonsag inicializalas</span>
tan1<span class="token punctuation">.</span>osztaly <span class="token operator">=</span> <span class="token char">&#39;B&#39;</span><span class="token punctuation">;</span> <span class="token comment">// osztaly tulajdonsag inicializalas</span>
tan1<span class="token punctuation">.</span><span class="token function">evfolyamotLep</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// evfolyamotLep metodus hivas</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az osztály definiálása során megadott tulajdonságokat rögtön inicializálhatjuk is a szokásos módon. ha egy tulajdonságot nem inicializálunk, annak kezdőértéke szám típusú változó esetén nulla, karakter esetén <code>/u0000</code>, logikai típus esetén <code>false</code>, minden egyéb esetben pedig <code>null</code> lesz. Egy osztálynak lehet konstans tulajdonsága is.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span>
    
    <span class="token keyword">final</span> <span class="token class-name">String</span> <span class="token constant">ISKOLANEVE</span> <span class="token operator">=</span> <span class="token string">&quot;Unknown School&quot;</span><span class="token punctuation">;</span> <span class="token comment">// konstans tag int evfolyam, </span>
    iskolakezdesEve <span class="token operator">=</span> <span class="token number">2017</span><span class="token punctuation">;</span> <span class="token comment">// inicializalas </span>
    <span class="token class-name">String</span> nev<span class="token punctuation">;</span>
    <span class="token keyword">char</span> osztaly<span class="token punctuation">;</span>

    <span class="token keyword">void</span> <span class="token function">evfolyamotLep</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> 
        evfolyam <span class="token operator">+=</span> <span class="token number">1</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="tulajdonsagok-es-metodusok-lathatosaga" tabindex="-1"><a class="header-anchor" href="#tulajdonsagok-es-metodusok-lathatosaga" aria-hidden="true">#</a> Tulajdonságok és metódusok láthatósága</h3><p>Egy osztály tulajdonságaira és metódusaira is alkalmazhatunk módosítókat, mellyel meghatározhatjuk, hogy azokat más osztályok elérhetik illetve hívhatják vagy sem. Ha egy tulajdonságot vagy metódust módosító nélkül definiálunk, akkor ezeket az adott csomagban definiált osztályok elérik – ezeket <strong>félnyilvános tagoknak</strong> nevezzük.</p><p>Amennyiben az egyes tagok definíciója elé a public kulcsszót írjuk, úgy ezek a tagok kívülről elérhetők azaz minden olyan objektum hozzájuk fér, amelyik az osztályt is láthatja. Az ilyen tulajdonságokat és metódusokat <strong>nyilvános tagoknak</strong> nevezzük.</p><p>Ha pedig egy tagot el szeretnénk rejteni, azt a private módosítóval érhetjük el. A <strong>privát tagok</strong> más osztályból nem hivatkozhatók, de az adott osztályon belül természetesen elérhetők maradnak.</p><div class="hint-container tip"><p class="hint-container-title">INFO</p><p>A gyakorlatban az osztályok tulajdonságait privát tagként szoktuk megadni, azok értékének lekérdezését és módosítását metódusok segítségével valósítjuk meg. Ha egy osztályban definiálunk egy Name tulajdonságot, az ő értékét visszaadó metódust getName-ként, az értékét beállító metódust pedig setName-ként szokás elnevezni. Ezeket nevezzük getter és setter metódusoknak.</p></div><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span>

	<span class="token keyword">private</span> <span class="token class-name">String</span> nev<span class="token punctuation">;</span>
	<span class="token keyword">private</span> <span class="token class-name">String</span> <span class="token constant">ISKOLANEVE</span> <span class="token operator">=</span> <span class="token string">&quot;Unknown School&quot;</span><span class="token punctuation">;</span>
	<span class="token keyword">private</span> <span class="token keyword">int</span> evfolyam<span class="token punctuation">,</span> iskolakezdesEve <span class="token operator">=</span> <span class="token number">2017</span><span class="token punctuation">;</span>
	<span class="token keyword">private</span> <span class="token keyword">char</span> osztaly<span class="token punctuation">;</span>
	
	<span class="token keyword">public</span> <span class="token class-name">String</span> <span class="token function">getNev</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">return</span> nev<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
	
	<span class="token keyword">public</span> <span class="token keyword">int</span> <span class="token function">getEvfolyam</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">return</span> evfolyam<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
	
	<span class="token keyword">public</span> <span class="token keyword">char</span> <span class="token function">getOsztaly</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">return</span> osztaly<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setNev</span><span class="token punctuation">(</span><span class="token class-name">String</span> nev<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>nev <span class="token operator">=</span> nev<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>

	<span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setEvfolyam</span><span class="token punctuation">(</span><span class="token keyword">int</span> evfolyam<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>evfolyam <span class="token operator">=</span> evfolyam<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
	
	<span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setOsztaly</span><span class="token punctuation">(</span><span class="token keyword">char</span> osztaly<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>osztaly <span class="token operator">=</span> osztaly<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
	
	<span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">evfolyamotLep</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		evfolyam <span class="token operator">+=</span> <span class="token number">1</span><span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Mint azt a fenti példa is mutatja, egy metódusban a <strong>this</strong> kulcsszóval hivatkozhatunk az osztály aktuális példányára. Erre akkor lehet szükség például, ha egy metódus paramétere megegyezik az osztály egy tagjának nevével – ilyenkor a formális paraméter elfedi az osztály tulajdonságát, így arra csak a <code>this</code> kulcsszó segítségével hivatkozhatunk.</p><div class="hint-container tip"><p class="hint-container-title">INFO</p><p>A metódusok visszatérési értékét a return kulcsszó után írjuk. Az adott visszatérési érték lehet összetett kifejezés is.</p></div><p>Egy osztálynak több azonos nevű metódusa is lehet, amennyiben azok különböző szignatúrával, azaz különböző nevű vagy típusú paraméterekkel rendelkeznek. Ilyenkor ugyanis a metódus hívásakor a megadott paraméterek száma és típusa meghatározza, hogy az adott metódus melyik példányát hívjuk. Ezt nevezzük az adott <strong>metódus túlterhelésének</strong>. Egy osztály konstruktorát is túlterhelhetjük. Mindkettőre láttunk már példát az egyes típusosztályoknál: a <code>String</code> típusnak többféle szignatúrával rendelkező konstruktora adott; a <code>valueOf</code> metódus pedig tetszőleges típusú paraméterrel hívható.</p><p>Az <code>evfolyamotLep</code> metódus túlterhelésére mutat példát az alábbi kódrészlet.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span>
	
    <span class="token keyword">private</span> <span class="token keyword">int</span> evfolyam<span class="token punctuation">,</span> iskolakezdesEve <span class="token operator">=</span> <span class="token number">2017</span><span class="token punctuation">;</span>
	<span class="token keyword">private</span> <span class="token keyword">char</span> osztaly<span class="token punctuation">;</span>
	
	<span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">evfolyamotLep</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		evfolyam <span class="token operator">+=</span> <span class="token number">1</span><span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
	
	<span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">evfolyamotLep</span><span class="token punctuation">(</span><span class="token keyword">int</span> evfolyam<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>evfolyam <span class="token operator">=</span> evfolyam<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
	
	<span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">evfolyamotLep</span><span class="token punctuation">(</span><span class="token keyword">int</span> evfolyam<span class="token punctuation">,</span> <span class="token keyword">char</span> osztaly<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>evfolyam <span class="token operator">=</span> evfolyam<span class="token punctuation">;</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>osztaly <span class="token operator">=</span> osztaly<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="konstruktor-definialasa" tabindex="-1"><a class="header-anchor" href="#konstruktor-definialasa" aria-hidden="true">#</a> Konstruktor definiálása</h3><p>Az osztály konstruktora az a programkód, amely az osztály példányosításakor automatikusan lefut. A konstruktorban szokás inicializálni a legfontosabb tulajdonságokat. A konstruktor nem metódus, nem is tekinthető tagnak, hiszen nem öröklődik.</p><div class="hint-container tip"><p class="hint-container-title">FONTOS</p><p>A konstruktor neve meg kell egyezzen az osztály nevével, és közvetlenül nem hívható, csak példányosításkor. A konstruktornak nincs visszatérési értéke, de a <code>void</code> kulcsszót sem kell kiírnunk. A konstruktort <code>public</code> módosítóval szoktuk létrehozni.</p></div><p>Konstruktora tulajdonképpen minden osztálynak van, akkor is, ha mi nem hozunk létre. Ilyenkor egy nyilvános, paraméter nélküli ún. <strong>implicit konstruktor</strong> jön létre, amelynek a törzse üres, és a programkódban nem jelenik meg.</p><p>Egészítsük ki a Tanulo osztályt egy konstruktorral, amely beállítja a név, évfolyam és osztály tulajdonságok értékeit!</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span>
	<span class="token keyword">private</span> <span class="token class-name">String</span> nev<span class="token punctuation">;</span>
	<span class="token keyword">private</span> <span class="token keyword">final</span> <span class="token class-name">String</span> <span class="token constant">ISKOLANEVE</span> <span class="token operator">=</span> <span class="token string">&quot;Unknown School&quot;</span><span class="token punctuation">;</span>
	<span class="token keyword">private</span> <span class="token keyword">int</span> evfolyam<span class="token punctuation">,</span> iskolakezdesEve <span class="token operator">=</span> <span class="token number">2017</span><span class="token punctuation">;</span>
	<span class="token keyword">private</span> <span class="token keyword">char</span> osztaly<span class="token punctuation">;</span>

	<span class="token keyword">public</span> <span class="token class-name">Tanulo</span><span class="token punctuation">(</span><span class="token class-name">String</span> nev<span class="token punctuation">,</span> <span class="token keyword">int</span> evfolyam<span class="token punctuation">,</span> <span class="token keyword">char</span> osztaly<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>nev <span class="token operator">=</span> nev<span class="token punctuation">;</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>evfolyam <span class="token operator">=</span> evfolyam<span class="token punctuation">;</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>osztaly <span class="token operator">=</span> osztaly<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
	<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token punctuation">}</span>
<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token class-name">Tanulo</span> tan2 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Tanulo</span><span class="token punctuation">(</span><span class="token string">&quot;Nagy Lajos&quot;</span><span class="token punctuation">,</span> <span class="token number">13</span><span class="token punctuation">,</span> <span class="token char">&#39;B&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A kódrészlet utolsó sora azt mutatja, hogyan hívjuk meg a fent definiált konstruktort.</p><div class="hint-container tip"><p class="hint-container-title">INFO</p><p>Mivel a java automatikus szemétgyűjtő mechanizmusa (garbage Collector) révén a már nem használt objektumok automatikusan törlődnek a memóriából, nincs szükség destruktorra – a nyelv nem is rendelkezik ilyen szerkezettel.</p></div><p>Osztályváltozónak nevezzük azt a tulajdonságot, amely nem az osztály egyes példányaihoz, hanem az osztály egészéhez kapcsolódik. Míg a példányváltozókból minden az adott osztályból létrehozott objektumnak lesz egy példánya, addig az osztályváltozókból csak egyetlen egy létezik. Osztályváltozót abban az esetben szokás létrehozni, ha az osztálynak is van olyan állapota, melyet ebben tárolni szeretnénk.<br> Hasonlóképpen osztályszintű metódusokat is létrehozhatunk az adott osztály műveleteinek megvalósítására. Az osztálymetódusokra azonban vonatkozik pár szabály.</p><div class="hint-container tip"><p class="hint-container-title">FONTOS</p><p>Az osztálymetódusok csak az osztályváltozókhoz férhetnek hozzá. Az osztálymetódusban nem használhatjuk a this kulcsszót, hiszen osztályszinten nincs értelme az osztály aktuális példányára hivatkozni.</p></div><p>Az osztálymetódusok akkor is végrehajthatók, ha az osztálynak nincs még egyetlen példánya sem. Osztályváltozót, illetve osztálymetódust a <code>static</code> kulcsszóval definiálhatunk. A <code>Tanulo</code> osztályban vezessünk be egy olyan osztályváltozót, amely a már létrehozott példányok számát tárolja. Ez az érték nyilvánvalóan nem lehet példányváltozó, hiszen az egyes példányok nem tudnak egymás létezéséről – az osztály azonban értesül egy-egy újabb példány létrejöttéről: a konstruktor hívásakor.</p><p>Hozzunk létre egy osztálymetódust is a példányok aktuális számának lekérdezésére.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span>
		<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
		<span class="token keyword">private</span> <span class="token keyword">static</span> <span class="token keyword">int</span> tanulokSzama <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">// osztalyszintu tag</span>
		<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
	
		<span class="token keyword">public</span> <span class="token class-name">Tanulo</span><span class="token punctuation">(</span><span class="token class-name">String</span> nev<span class="token punctuation">,</span> <span class="token keyword">int</span> evfolyam<span class="token punctuation">,</span> <span class="token keyword">char</span> osztaly<span class="token punctuation">)</span> <span class="token punctuation">{</span>
			<span class="token keyword">this</span><span class="token punctuation">.</span>nev <span class="token operator">=</span> nev<span class="token punctuation">;</span>
			<span class="token keyword">this</span><span class="token punctuation">.</span>evfolyam <span class="token operator">=</span> evfolyam<span class="token punctuation">;</span>
			<span class="token keyword">this</span><span class="token punctuation">.</span>osztaly <span class="token operator">=</span> osztaly<span class="token punctuation">;</span>
			tanulokSzama <span class="token operator">+=</span> <span class="token number">1</span><span class="token punctuation">;</span>
		<span class="token punctuation">}</span>
	
		<span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">int</span> <span class="token function">getTanulokSzama</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
			<span class="token keyword">return</span> tanulokSzama<span class="token punctuation">;</span>
		<span class="token punctuation">}</span>
	<span class="token punctuation">}</span>
	<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
	<span class="token keyword">int</span> db <span class="token operator">=</span> <span class="token class-name">Tanulo</span><span class="token punctuation">.</span><span class="token function">getTanulokSzama</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A fenti kódrészlet utolsó sora azt mutatja, hogyan hivatkozhatunk az osztályváltozókra (nyilvános tag esetén) és az osztálymetódusokra másik osztályból: az osztály azonosítóján keresztül. Egy osztályváltozót is inicializálhatunk – ez az értékadás természetesen csak egyetlen egyszer hajtódik végre: az osztály definiálásakor. Az egyes objektumok példányosításakor csak a példányváltozók kapnak kezdőértéket.</p><h3 id="a-java-foprogram-mint-osztalyszintu-metodus" tabindex="-1"><a class="header-anchor" href="#a-java-foprogram-mint-osztalyszintu-metodus" aria-hidden="true">#</a> A Java főprogram mint osztályszintű metódus</h3><p>Számtalan Java programot elkészítettünk már, de vizsgáljuk most meg, mi is egy Java program.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Main</span> <span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// program</span>
    <span class="token punctuation">}</span> 
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Valójában tehát egy <code>Main</code> nevű osztály statikus, azaz osztályszintű, nyilvános és visszatérési értékkel nem rendelkező metódusát implementáljuk a főprogram megírásakor, amely egy <code>String</code> alaptípusú tömb paraméterrel rendelkezik. Ez a metódus a <code>Main</code> osztály példányosítása nélkül is hívható, hiszen osztályszintű.</p><div class="hint-container tip"><p class="hint-container-title">FONTOS</p><p>Ha a <code>Main</code> osztályon belül szeretnénk egy műveletet kiszervezni egy másik metódusba, annak osztályszintű metódusnak kell lennie, hiszen a <code>Main</code> osztály nincs példányosítva.</p></div><h2 id="oroklodes" tabindex="-1"><a class="header-anchor" href="#oroklodes" aria-hidden="true">#</a> Öröklődés</h2><h3 id="oroklodes-1" tabindex="-1"><a class="header-anchor" href="#oroklodes-1" aria-hidden="true">#</a> Öröklődés</h3><p>Osztályt létrehozhatunk úgy, hogy teljesen újként definiáljuk, de egy már meglevő osztályból is <strong>származtathatjuk</strong> - ezt nevezzük <strong>öröklődésnek</strong>. A Javában nincs többszörös öröklődés, azaz minden osztálynak csupán egyetlen őse lehet.</p><div class="hint-container tip"><p class="hint-container-title">INFO</p><p>Javában az <code>Object</code> osztály minden osztály ősosztálya, azaz a legáltalánosabb osztály.</p></div><p>Amikor egy osztályt egy már meglevőből származtatunk, kiegészíthetjük azt új tagokkal, azaz új tulajdonságokkal és metódusokkal. A származtatást az <code>extends</code> kulcsszóval tehetjük meg.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">VegzosTanulo</span> <span class="token keyword">extends</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span> 
    <span class="token keyword">private</span> <span class="token keyword">double</span> erettsegiAtlag<span class="token punctuation">;</span>
    <span class="token class-name">String</span> egyetem<span class="token punctuation">;</span>
    <span class="token class-name">String</span> szak<span class="token punctuation">;</span>
    
    <span class="token keyword">public</span> <span class="token keyword">double</span> <span class="token function">getErettsegiAtlag</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> 
        <span class="token keyword">return</span> erettsegiAtlag<span class="token punctuation">;</span> 
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setTovabbTanulas</span><span class="token punctuation">(</span><span class="token class-name">String</span> egyetem<span class="token punctuation">,</span> <span class="token class-name">String</span> szak<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
        <span class="token keyword">this</span><span class="token punctuation">.</span>egyetem <span class="token operator">=</span> egyetem<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>szak <span class="token operator">=</span> szak<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A fenti <code>vegzosTanulo</code> osztály tehát a <code>Tanulo</code> osztály <strong>leszármazottja</strong> vagy <strong>gyermeke</strong>, a <code>Tanulo</code> pedig a <code>vegzosTanulo</code> <strong>szülője</strong>, vagyis <strong>őse</strong>.<br> Javában a <code>public</code> és <code>protected</code> módosítókon kívül egy harmadik is a rendelkezésünkre áll: ha egy tulajdonságot vagy metódust a <code>protected</code> módosítóval hozunk létre, úgy azt csak az adott csomagban definiált osztályokból érhetjük el, illetve minden belőle származtatott osztályból.</p><p>A gyermekosztály örökli a szülőosztály valamennyi publikus, <code>protected</code> és félnyilvános, valamint összes osztályszintű tagját. A <code>private</code> tulajdonságokat is eléri a hozzá definiált nyilvános metódusokon keresztül – például lekérdezheti az értékét a getter, és módosíthatja a setter metódusokat használva. A privát metódusok nem öröklődnek.</p><p>A konstruktort a gyermekosztály nem örökli, azonban a gyermekosztály konstruktorából meghívhatjuk a szülőosztály konstruktorát a <code>super</code> kulcsszó használatával.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">VegzosTanulo</span> <span class="token keyword">extends</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token keyword">double</span> erettsegiAtlag<span class="token punctuation">;</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
    <span class="token keyword">public</span> <span class="token class-name">VegzosTanulo</span><span class="token punctuation">(</span><span class="token class-name">String</span> nev<span class="token punctuation">,</span> <span class="token keyword">char</span> osztaly<span class="token punctuation">,</span> <span class="token keyword">double</span> erettsAtlag<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">super</span><span class="token punctuation">(</span>nev<span class="token punctuation">,</span> <span class="token number">13</span><span class="token punctuation">,</span> osztaly<span class="token punctuation">)</span><span class="token punctuation">;</span>
        erettsegiAtlag <span class="token operator">=</span> erettsAtlag<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token punctuation">}</span> 
<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token class-name">VegzosTanulo</span> vtan <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">VegzosTanulo</span><span class="token punctuation">(</span><span class="token string">&quot;Nagy Lajos&quot;</span><span class="token punctuation">,</span> <span class="token char">&#39;B&#39;</span><span class="token punctuation">,</span> <span class="token number">4.235</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A fenti kódrészletben az új osztály konstruktorából meghívjuk tehát a <code>Tanulo</code> osztály konstruktorát, amely beállítja a név, évfolyam és osztály változók értékeit, és megnöveli a tanulók számát nyilvántartó osztályváltozó értékét is.</p><p>A <code>this</code> kulcsszót pedig arra is használhatjuk, hogy az adott osztályban definiált másik konstruktort hívjuk vele.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">VegzosTanulo</span> <span class="token keyword">extends</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token keyword">double</span> erettsegiAtlag<span class="token punctuation">;</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
    <span class="token keyword">public</span> <span class="token class-name">VegzosTanulo</span><span class="token punctuation">(</span><span class="token class-name">String</span> nev<span class="token punctuation">,</span> <span class="token keyword">char</span> osztaly<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
        <span class="token keyword">super</span><span class="token punctuation">(</span>nev<span class="token punctuation">,</span> <span class="token number">13</span><span class="token punctuation">,</span> osztaly<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> 
    
    <span class="token keyword">public</span> <span class="token class-name">VegzosTanulo</span><span class="token punctuation">(</span><span class="token class-name">String</span> nev<span class="token punctuation">,</span> <span class="token keyword">char</span> osztaly<span class="token punctuation">,</span> <span class="token keyword">double</span> erettsAtlag<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
        <span class="token keyword">this</span><span class="token punctuation">(</span>nev<span class="token punctuation">,</span> osztaly<span class="token punctuation">)</span><span class="token punctuation">;</span>
        erettsegiAtlag <span class="token operator">=</span> erettsAtlag<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
   <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> 
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A fenti példában az első konstruktor meghívja a <code>Tanulo</code> osztályban definiált konstruktort, a második konstruktor pedig előbb meghívja az első konstruktort, majd inicializálja az érettségi átlagot tároló példányváltozót. Bármelyik konstruktort hívjuk is utána a példányosításkor, a szülőosztály konstruktora le fog futni.</p><h3 id="statikus-es-dinamikus-tipus" tabindex="-1"><a class="header-anchor" href="#statikus-es-dinamikus-tipus" aria-hidden="true">#</a> Statikus és dinamikus típus</h3><p>Mivel a <code>VegzosTanulo</code> a <code>Tanulo</code> osztály leszármazottja, egy <code>Tanulo</code> típusú változónak értékül adható egy <code>VegzosTanulo</code> típusú objektum is, hiszen az annak kiterjesztése csupán: minden olyan tulajdonsággal és metódussal rendelkezik, amivel az őse.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">Tanulo</span> tan <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Tanulo</span><span class="token punctuation">(</span><span class="token string">&quot;Kiss Piroska&quot;</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">,</span> <span class="token char">&#39;B&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">VegzosTanulo</span> vtan <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">VegzosTanulo</span><span class="token punctuation">(</span><span class="token string">&quot;Nagy Lajos&quot;</span><span class="token punctuation">,</span> <span class="token char">&#39;B&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
tan <span class="token operator">=</span> vtan<span class="token punctuation">;</span>
vtan <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token class-name">VegzosTanulo</span><span class="token punctuation">)</span>tan<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az értékadó utasítás után a tan objektumváltozó <strong>statikus típusa</strong> <code>Tanulo</code> lesz, a <strong>dinamikus típusa</strong> viszont <code>VegzosTanulo</code>. Egy változó statikus típusa a program futása alatt végig változatlan – ez az a típus, amit a változó deklarációjakor megadtunk; dinamikus típusa viszont a program futása során változhat.</p><p>A <code>vtan</code> változónak pedig értékül adhatjuk a <code>tan</code> objektumot, hiszen annak dinamikus típusa <code>VegzosTanulo</code>. Ilyenkor az objektumváltozó előtt zárójelben meg kell adnunk a dinamikus típust – ezt javában <strong>típuskényszerítésnek</strong> vagy <strong>explicit típuskonverziónak</strong> hívják.</p><p>Ha például egy tömbben kívánjuk tárolni az objektumainkat, úgy ha a tömb alaptípusa <code>Tanulo</code>, abba a <code>VegzosTanulo</code> típusú objektumainkat is tárolhatjuk. hasonlóképpen az általánosabb típusú paraméterrel rendelkező metódus hívható speciálisabb típusú objektummal is.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Iskola</span> <span class="token punctuation">{</span>
    <span class="token keyword">static</span> <span class="token keyword">boolean</span> <span class="token function">egyOsztalybaJarnak</span><span class="token punctuation">(</span><span class="token class-name">Tanulo</span> tan1<span class="token punctuation">,</span> <span class="token class-name">Tanulo</span> tan2<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token punctuation">(</span>tan1<span class="token punctuation">.</span><span class="token function">getEvfolyam</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">==</span> tan2<span class="token punctuation">.</span><span class="token function">getEvfolyam</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">&amp;&amp;</span> 
                tan1<span class="token punctuation">.</span><span class="token function">getOsztaly</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">==</span> tan2<span class="token punctuation">.</span><span class="token function">getOsztaly</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token class-name">Tanulo</span> tan1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Tanulo</span><span class="token punctuation">(</span><span class="token string">&quot;Tóth Brúnó&quot;</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">,</span> <span class="token char">&#39;B&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">Tanulo</span> tan2 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Tanulo</span><span class="token punctuation">(</span><span class="token string">&quot;Kiss Piroska&quot;</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">,</span> <span class="token char">&#39;B&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">VegzosTanulo</span> vtan <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">VegzosTanulo</span><span class="token punctuation">(</span><span class="token string">&quot;Nagy Lajos&quot;</span><span class="token punctuation">,</span> <span class="token char">&#39;B&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">boolean</span> b <span class="token operator">=</span> <span class="token class-name">Iskola</span><span class="token punctuation">.</span><span class="token function">egyOsztalybaJarnak</span><span class="token punctuation">(</span>tan1<span class="token punctuation">,</span> tan2<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// érték: true </span>
b <span class="token operator">=</span> <span class="token class-name">Iskola</span><span class="token punctuation">.</span><span class="token function">egyOsztalybaJarnak</span><span class="token punctuation">(</span>tan1<span class="token punctuation">,</span> vtan<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// érték: false</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Látjuk, hogy a fenti Iskola osztályban definiált osztálymetódusnak bár két <code>Tanulo</code> típusú paramétere van, <code>VegzosTanulo</code> típusú értékkel is hívható. Az ilyen metódusokban azonban nyilvánvalóan csak olyan tagokra hivatkozhatunk, melyeket a <code>Tanulo</code> osztályban definiáltunk.</p><div class="hint-container warning"><p class="hint-container-title">FONTOS</p><p><code>Object</code> típusú változónak tetszőleges objektum értékül adható.</p></div><h3 id="metodusok-feluldefinialasa" tabindex="-1"><a class="header-anchor" href="#metodusok-feluldefinialasa" aria-hidden="true">#</a> Metódusok felüldefiniálása</h3><p>A gyermekosztály hozzáfér a szülőosztályban definiált publikus, <code>protected</code> és félnyilvános metódusokhoz, és azokat felül is definiálhatja. Amennyiben a gyermekosztály egy öröklött metódushoz saját implementációt készít, úgy az adott metódust <strong>felüldefiniálja</strong>. Ilyenkor a gyermekosztály metódusának hívásakor az új implementáció fog lefutni. Az eredeti kód csak a felüldefiniálás során érhető el a <code>super</code> kulcsszó használatával. A privát metódusokat nem tudjuk felüldefiniálni, mivel azok nem öröklődnek.</p><p>Az alábbi példában a havi osztálypénz kiszámítását végző metódust definiáljuk felül a <code>vegzosTanulo</code> osztály definíciójában. A felüldefiniáló metódus kidolgozásából azonban meghívjuk az eredetit.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span> 
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
    <span class="token keyword">private</span> <span class="token keyword">int</span> evesOsztalypenz <span class="token operator">=</span> <span class="token number">10000</span><span class="token punctuation">;</span> 
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
    <span class="token keyword">public</span> <span class="token keyword">int</span> <span class="token function">szamolHaviOsztalypenz</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> evesOsztalypenz <span class="token operator">/</span> <span class="token number">10</span><span class="token punctuation">;</span>  
    <span class="token punctuation">}</span> 
<span class="token punctuation">}</span> 

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">VegzosTanulo</span> <span class="token keyword">extends</span> <span class="token class-name">Tanulo</span> <span class="token punctuation">{</span> 
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
    <span class="token keyword">private</span> <span class="token keyword">int</span> ballagasKoltsegek<span class="token punctuation">;</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
    <span class="token keyword">public</span> <span class="token keyword">int</span> <span class="token function">szamolHaviOsztalypenz</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token keyword">super</span><span class="token punctuation">.</span><span class="token function">szamolHaviOsztalypenz</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">+</span> ballagasKoltsegek <span class="token operator">/</span> <span class="token number">10</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> 
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> 
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Futási időben, ha egy objektum valamely metódusát hívjuk, mindig az objektum dinamikus típusához tartozó metódus fog lefutni.</p><div class="hint-container warning"><p class="hint-container-title">INFO</p><p>A felüldefiniáló metódust ugyanúgy kell elneveznünk, mint az eredeti metódust és a szignatúrájuknak is egyezni kell. A visszatérési értékük típusának szintén azonosnak kell lennie és a felüldefiniáló metódus láthatósági kategóriája nem lehet szűkebb mint az eredeti metódusé.</p><p>Ha egy túlterhelt metódust definiálunk felül, úgy csak a vele pontosan egyező szignatúrájút írjuk felül.</p></div><p>Az osztálymetódusokat nem lehet felüldefiniálni, csak elfedni – futási időben ugyanis az objektum statikus típusának megfelelő osztálymetódusa fog lefutni. Egy osztályban definiált osztálymetódus elfedi a vele megegyező nevű és szignatúrájú, szülőosztályban definiált osztálymetódust. Példánymetódust osztálymetódussal nem szabad elfedni.</p><p>Az osztály tulajdonságai szintén elfedhetők a belőle származtatott osztályban.</p><h3 id="absztrakt-es-vegleges-osztalyok" tabindex="-1"><a class="header-anchor" href="#absztrakt-es-vegleges-osztalyok" aria-hidden="true">#</a> Absztrakt és végleges osztályok</h3><p>Amikor komplett osztályhierarchiát valósítunk meg Javában, szükségünk lehet olyan osztályok definiálására is, melyeket nem kívánunk példányosítani, csak származtatni belőle más osztályokat. Az ilyen osztályokban tulajdonképpen a belőle származtatott osztályok közös tulajdonságait és kidolgozandó metódusait írjuk le. Az ilyen osztályokat <strong>absztrakt osztályoknak</strong> nevezzük, és az <code>abstract</code> kulcsszóval jelöljük. Az absztrakt osztálynak pedig azon metódusait, melynek konkrét megvalósítását a gyermekosztályokra hagyjuk, <strong>absztrakt metódusoknak</strong> nevezzük.</p><p>Az alábbi példában definiálunk egy absztrakt <code>Negyszog</code> osztályt, melynek lesz egy megvalósított kerületet számító és egy absztrakt területet számító metódusa. Ebből származtatjuk a <code>Teglalap</code> és <code>Paralelogramma</code> osztályokat, melyekben implementáljuk az absztrakt <code>teruletSzamit</code> metódust.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">abstract</span> <span class="token keyword">class</span> <span class="token class-name">Negyszog</span> <span class="token punctuation">{</span>
	<span class="token keyword">protected</span> <span class="token keyword">double</span> aOldal<span class="token punctuation">,</span> bOldal<span class="token punctuation">;</span>

	<span class="token keyword">protected</span> <span class="token keyword">double</span> <span class="token function">keruletSzamit</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">return</span> <span class="token number">2</span> <span class="token operator">*</span> <span class="token punctuation">(</span>aOldal <span class="token operator">+</span> bOldal<span class="token punctuation">)</span><span class="token punctuation">;</span>
	<span class="token punctuation">}</span>

	<span class="token keyword">protected</span> <span class="token keyword">abstract</span> <span class="token keyword">double</span> <span class="token function">teruletSzamit</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">class</span> <span class="token class-name">Teglalap</span> <span class="token keyword">extends</span> <span class="token class-name">Negyszog</span> <span class="token punctuation">{</span>
	<span class="token keyword">public</span> <span class="token class-name">Teglalap</span><span class="token punctuation">(</span><span class="token keyword">double</span> aOldal<span class="token punctuation">,</span> <span class="token keyword">double</span> bOldal<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>aOldal <span class="token operator">=</span> aOldal<span class="token punctuation">;</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>bOldal <span class="token operator">=</span> bOldal<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>

	<span class="token keyword">protected</span> <span class="token keyword">double</span> <span class="token function">teruletSzamit</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">return</span> aOldal <span class="token operator">*</span> bOldal<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token keyword">class</span> <span class="token class-name">Paralelogramma</span> <span class="token keyword">extends</span> <span class="token class-name">Negyszog</span> <span class="token punctuation">{</span>
	<span class="token keyword">protected</span> <span class="token keyword">double</span> aMagassag<span class="token punctuation">,</span> bMagassag<span class="token punctuation">;</span>

	<span class="token keyword">public</span> <span class="token class-name">Paralelogramma</span><span class="token punctuation">(</span><span class="token keyword">double</span> aOldal<span class="token punctuation">,</span> <span class="token keyword">double</span> bOldal<span class="token punctuation">,</span> <span class="token keyword">double</span> aMag<span class="token punctuation">,</span> <span class="token keyword">double</span> bMag<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>aOldal <span class="token operator">=</span> aOldal<span class="token punctuation">;</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>bOldal <span class="token operator">=</span> bOldal<span class="token punctuation">;</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>aMagassag <span class="token operator">=</span> aMag<span class="token punctuation">;</span>
		<span class="token keyword">this</span><span class="token punctuation">.</span>bMagassag <span class="token operator">=</span> bMag<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>

	<span class="token keyword">protected</span> <span class="token keyword">double</span> <span class="token function">teruletSzamit</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">return</span> aOldal <span class="token operator">*</span> aMagassag<span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Main</span> <span class="token punctuation">{</span>
	<span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token class-name">Teglalap</span> t <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Teglalap</span><span class="token punctuation">(</span><span class="token number">12</span><span class="token punctuation">,</span> <span class="token number">9</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
		<span class="token class-name">Paralelogramma</span> p <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Paralelogramma</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">12.5</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
		<span class="token keyword">double</span> tKer <span class="token operator">=</span> t<span class="token punctuation">.</span><span class="token function">keruletSzamit</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ertek: 42</span>
		<span class="token keyword">double</span> tTer <span class="token operator">=</span> t<span class="token punctuation">.</span><span class="token function">teruletSzamit</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ertek: 108</span>
		<span class="token keyword">double</span> pKer <span class="token operator">=</span> p<span class="token punctuation">.</span><span class="token function">keruletSzamit</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ertek: 45</span>
		<span class="token keyword">double</span> pTer <span class="token operator">=</span> p<span class="token punctuation">.</span><span class="token function">teruletSzamit</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ertek: 50</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Végleges osztálynak</strong> nevezzük azt az osztályt, amely nem örökíthető – azaz belőle származtatással nem hozhatunk létre új osztályt. Egy osztály metódusa pedig akkor végleges metódus, ha azt származtatás során nem lehet felüldefiniálni. A véglegességet osztályok és metódusok esetén is a <strong>final</strong> kulcsszóval adhatjuk meg.<br> Az <strong>abstract</strong> és <strong>final</strong> módosítók kizárják egymást.</p><h2 id="sajat-kivetelosztaly" tabindex="-1"><a class="header-anchor" href="#sajat-kivetelosztaly" aria-hidden="true">#</a> Saját kivételosztály</h2><p>Gyakran előfordul, hogy a beépített kivételosztályok helyett saját kivétel létrehozására van szükség.</p><h3 id="sajat-kivetelosztaly-1" tabindex="-1"><a class="header-anchor" href="#sajat-kivetelosztaly-1" aria-hidden="true">#</a> Saját kivételosztály</h3><p>Mivel a kivétel is egy objektum, az osztályok definiálását ismerve kivételosztályt is létre tudunk már hozni.</p><div class="hint-container tip"><p class="hint-container-title">INFO</p><p>Minden kivételosztály ősosztálya az Exception, tehát ebből kell származtatnunk. Az általunk definiált kivételosztály mindig ellenőrzött.</p></div><p>Készítsünk saját kivételosztályt, amelyet akkor fogunk kiváltani, ha a felhasználó olyan oldalakkal definiál egy háromszöget, hogy azok alapján a háromszög nem szerkeszthető.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">NemSzerkeszthetoException</span> <span class="token keyword">extends</span> <span class="token class-name">Exception</span> <span class="token punctuation">{</span>
	  <span class="token keyword">public</span> <span class="token class-name">NemSzerkeszthetoException</span><span class="token punctuation">(</span><span class="token class-name">String</span> uzenet<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		    <span class="token keyword">super</span><span class="token punctuation">(</span>uzenet<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A kivételosztályunk csak egy konstruktorral rendelkezik, melynek kidolgozása az <code>Exception</code> osztály konstruktorának hívása. A kivételt egy sztring típusú üzenet paraméter megadásával példányosíthatjuk.</p><div class="hint-container danger"><p class="hint-container-title">FONTOS</p><p>Ha egy metódus implementációjában valamilyen beépített vagy általunk létrehozott kivételt dobunk, úgy a metódus fejében fel kell sorolnunk ezen kivételosztályokat. Ez a felsorolás a metódus azonosítója után, a <code>throws</code> kulcsszóval kezdve tehető meg.</p></div><p>Készítsünk most egy haromszog osztályt, amely a konstruktorban bekéri a háromszög oldalait, és a fent létrehozott kivételt dobja amennyiben a háromszög nem szerkeszthető.</p><p>A kivételt az osztály konstruktorában fogjuk dobni, ám a kezelést arra a blokkra bízzuk, ahonnan a példányosítástörténik. Ezért a metódusfejében jeleznünk kell, hogy a metódus NemSzerkeszthetoException-t dobhat.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Haromszog</span> <span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token keyword">double</span> a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">;</span>
    
    <span class="token keyword">public</span> <span class="token class-name">Haromszog</span><span class="token punctuation">(</span><span class="token keyword">double</span> a<span class="token punctuation">,</span> <span class="token keyword">double</span> b<span class="token punctuation">,</span> <span class="token keyword">double</span> c<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">NemSzerkeszthetoException</span> <span class="token punctuation">{</span>
        <span class="token keyword">if</span><span class="token punctuation">(</span>a<span class="token operator">+</span>b<span class="token operator">&gt;</span>c <span class="token operator">&amp;&amp;</span> a<span class="token operator">+</span>c<span class="token operator">&gt;</span>b <span class="token operator">&amp;&amp;</span> b<span class="token operator">+</span>c<span class="token operator">&gt;</span>a<span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token keyword">this</span><span class="token punctuation">.</span>a <span class="token operator">=</span> a<span class="token punctuation">;</span>
            <span class="token keyword">this</span><span class="token punctuation">.</span>b <span class="token operator">=</span> b<span class="token punctuation">;</span>
            <span class="token keyword">this</span><span class="token punctuation">.</span>c <span class="token operator">=</span> c<span class="token punctuation">;</span>
        <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
            <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">NemSzerkeszthetoException</span><span class="token punctuation">(</span><span class="token string">&quot;Nem szerkesztheto!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Nézzük még meg, hogyan történik a <code>Haromszog</code> osztály példányosítása!</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">try</span> <span class="token punctuation">{</span>
	<span class="token class-name">Haromszog</span> h <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Haromszog</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">NemSzerkeszthetoException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
	<span class="token class-name">System</span><span class="token punctuation">.</span>err<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>e<span class="token punctuation">.</span><span class="token function">getMessage</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A catch-ág fejében létrehozunk egy <code>e</code> objektumváltozót, melybe a kivételobjektum kerül annak elkapásakor. A kivétel kezelése annyiból áll, hogy kiírjuk a hibakonzolra azt az üzenetet, mellyel a kivételt létrehozták – ezt pedig a kivételobjektum <code>getMessage</code> metódusa adja meg. Ezt a metódust az általunk definiált kivételosztály az <code>Exception</code> osztálytól örökölte.</p><h2 id="collection-interfesz" tabindex="-1"><a class="header-anchor" href="#collection-interfesz" aria-hidden="true">#</a> Collection interfész</h2><h3 id="az-interfesz-fogalma" tabindex="-1"><a class="header-anchor" href="#az-interfesz-fogalma" aria-hidden="true">#</a> Az interfész fogalma</h3><p>A Java programok alapvető építőkövei az osztályok, de van egy másik fontos fogalom, amely nem azonos az osztállyal: az interfész. Az <strong>interfész</strong> absztrakt metódusdeklarációk és konstansok gyűjteménye. Hasonlít egy absztrakt osztályhoz, de az interfésznek nincsenek adattagjai, és egyik metódusa sincs implementálva. Az interfész csak egy absztrakt felületet definiál, később kidolgozandó műveletek halmazát. Egy interfészt csak akkor tudunk használni, ha implementálja őt egy osztály. <strong>Egy osztály implementál egy interfészt</strong>, ha valamennyi, az interfészben definiált metódust implementálja. Az interfész hasonló absztrakciós szerepet tölt be, mint egy absztrakt ősosztály: minden olyan helyen, ahol egy adott interfész szerepel típusként, az interfészt implementáló bármely osztály példánya használható. Az interfészek között is van <strong>öröklődés</strong>, sőt, interfészeknél van <strong>többszörös öröklődés</strong>: egy interfésznek lehet több szülőinterfésze is. Az interfészeknek nincs ősinterfésze.</p><p>A <strong>Collections Framework</strong> egy olyan keretrendszer, amely összetett adatszerkezeteken, azaz gyűjteményeken alkalmazható műveleteket definiáló interfészekből; ezeket implementáló osztályokból és a gyűjteményeken alkalmazható algoritmusokból (pl. rendezés) áll.</p><p>A <em>Collection</em> interfész a gyűjteményhierarchia egyik gyökere, a legáltalánosabb interfész. Tulajdonképpen absztrakt interfész, mivel közvetlenül egyetlen osztály sem implementálja.</p><p>A <em>Collection</em> interfész leszármazottjai a <code>Set</code>, azaz halmaz interfész; a <code>SortedSet</code>, azaz rendezett halmaz interfész és a <code>List</code>, azaz lista interfész.</p><div class="hint-container tip"><p class="hint-container-title">INFO!</p><p>A Collection interfészt a <code>java.util</code> csomagban definiálták.</p></div><h3 id="iterator" tabindex="-1"><a class="header-anchor" href="#iterator" aria-hidden="true">#</a> Iterátor</h3><p>A gyűjtemények feldolgozásában segít az iterátor objektum, amely a gyűjtemény elemeit járja be. Minden gyűjteményhez adott egy iterátor, amely az <code>iterator()</code> metódussal kérhető le. Valójában az <code>Iterator</code> is egy interfész a <strong>Collections Frameworkben</strong>.</p><p>Nézzük meg, hogyan lehet iterátor segítségével kiírni egy tetszőleges gyűjtemény elemeit a képernyőre!</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">Iterator</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Long</span><span class="token punctuation">&gt;</span></span> it <span class="token operator">=</span> halmaz<span class="token punctuation">.</span><span class="token function">iterator</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">Long</span> elem <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
<span class="token keyword">while</span> <span class="token punctuation">(</span>it<span class="token punctuation">.</span><span class="token function">hasNext</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
	elem <span class="token operator">=</span> it<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
	<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>elem<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az iterátor használata olvashatóbbá teszi a kódot, és egyszerűbbé is, hiszen nem kell lekérdeznünk az adott gyűjtemény hosszát, sem indexszel vagy más módon hivatkozni az elemeire.</p><h3 id="halmaz-interfesz" tabindex="-1"><a class="header-anchor" href="#halmaz-interfesz" aria-hidden="true">#</a> Halmaz interfész</h3><p>A <code>Set</code> interfész a <code>Collection</code> interfész leszármazottja, és a halmaz adattípust valósítja meg. Ugyanazokat a metódusokat implementálja, mint amelyek a <code>Collection</code> interfészben adottak. Ám a halmaz jellemzőjéből adódóan bizonyos műveletek másképpen működnek: ha például egy olyan elemet teszünk az <code>add()</code> metódussal a halmazba, amely már szerepel benne, az nem kerül bele ismét.</p><p>A tömeges műveletek segítségével pedig az egyes halmazműveletek is megvalósítottak, hiszen az <code>addAll()</code>-lal két halmaz uniója képezhető, a <code>retainAll()</code> segítségével metszetet készíthetünk, a <code>removeAll()</code> használatával pedig két halmaz különbségét vehetjük. Két halmaz akkor egyenlő, ha ugyanazokat az elemeket tartalmazzák.</p><p>A <code>Set</code> halmaz egyik implementáló osztálya a <code>HashSet</code> osztály. A <code>HashSet</code> osztály rendelkezik egy kezdeti kapacitással, amelyet úgy érdemes megadni, hogy a tényleges elemszám kétszerese legyen (ez befolyásolhatja a halmaz feldolgozásának futási idejét). Ha nem tudjuk a halmaz tényleges elemszámát, úgy a kezdeti kapacitás állítását bízzuk a rendszerre.</p><p>Az alábbi példában 0 és 10 közé eső véletlenszámokat generálunk, melyeket egy halmazba pakolunk, majd kiírjuk őket a képernyőre.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">HashSet</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Long</span><span class="token punctuation">&gt;</span></span> halmaz <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">HashSet</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Long</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
	<span class="token class-name">Long</span> rand <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Long</span><span class="token punctuation">(</span><span class="token class-name">Math</span><span class="token punctuation">.</span><span class="token function">round</span><span class="token punctuation">(</span><span class="token class-name">Math</span><span class="token punctuation">.</span><span class="token function">random</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">*</span> <span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
	halmaz<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>rand<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token class-name">Iterator</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Long</span><span class="token punctuation">&gt;</span></span> it <span class="token operator">=</span> halmaz<span class="token punctuation">.</span><span class="token function">iterator</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> it<span class="token punctuation">.</span><span class="token function">hasNext</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
	<span class="token class-name">Long</span> l <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token class-name">Long</span><span class="token punctuation">)</span> it<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
	<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>l<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="rendezett-halmaz-interfesz" tabindex="-1"><a class="header-anchor" href="#rendezett-halmaz-interfesz" aria-hidden="true">#</a> Rendezett halmaz interfész</h3><p>A rendezett halmaz a <code>Set</code> halmazzal szemben az elemeit rendezve tárolja. Ha a <code>HashSet</code> halmazba egyszerű számokat teszünk, úgy előfordulhat, hogy elemeit egy iterátorral bejárva rendezetten kapjuk meg. Azonban ha a halmazba sztringeket rakunk, azokat rendezve csak egy rendezett halmaz fogja visszaadni. A rendezett halmazt a <code>SortedSet</code> interfész írja le, amely a <code>Set</code> interfész leszármazottja.<br> A <code>SortedSet</code> interfészt implementáló osztály a <code>TreeSet</code>. A rendezett halmaz segítségével könnyedén kereshetjük meg egy adathalmaz legkisebb és legnagyobb elemét. Az alábbi példában karakterláncokat olvasunk be a képernyőről, majd kiírjuk az ábécében legelöl és leghátul állót.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">TreeSet</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span> rHalmaz <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">TreeSet</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Adj meg ot szot!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">try</span> <span class="token punctuation">{</span>
	<span class="token keyword">for</span><span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i<span class="token operator">&lt;</span><span class="token number">5</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		 <span class="token class-name">String</span> szo <span class="token operator">=</span> r<span class="token punctuation">.</span><span class="token function">readLine</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
		 rHalmaz<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>szo<span class="token punctuation">)</span><span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span> <span class="token keyword">catch</span><span class="token punctuation">(</span><span class="token class-name">IOException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
	  <span class="token class-name">System</span><span class="token punctuation">.</span>err<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>e<span class="token punctuation">.</span><span class="token function">getMessage</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;ABC legelso elem: &quot;</span> <span class="token operator">+</span> rHalmaz<span class="token punctuation">.</span><span class="token function">first</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;ABC legutolso elem: &quot;</span> <span class="token operator">+</span> rHalmaz<span class="token punctuation">.</span><span class="token function">last</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="lista-interfesz" tabindex="-1"><a class="header-anchor" href="#lista-interfesz" aria-hidden="true">#</a> Lista interfész</h3><p>A <code>List</code> interfész a lista vagy sorozat adattípust írja le. A <code>List</code> interfész is a Collection leszármazottja. A lista egy elemet többször is tartalmazhat, elemeit azok pozíciója szerint is el lehet érni, és keresni is lehet közöttük.</p><p>A listának nem csak iterátora, hanem listaiterátora is van. Mivel a lista nem csak az elejétől a vége felé, hanem fordítva is bejárható, a listaiterátor nem csak <code>hasNext()</code> és <code>next()</code>, hanem <code>hasPrevious()</code> és <code>previous()</code> metódusokkal is rendelkezik. Kiegészítették továbbá a <code>nextIndex()</code> és <code>previousIndex()</code> műveletekkel, melyek a soronkövetkező elem indexét adják meg.</p><p>A lista tartalmaz néhány új metódust a Collection-ben definiáltakhoz képest, illetve néhány metódus működése megváltozott a lista működéséből adódóan. Az alábbi táblázat csak az új vagy módosult működésű metódusokat tartalmazza. A Collection interfésznél ismertetett valamennyi művelet alkalmazható a lista esetében is.</p><p>A <code>List</code> interfészt implementáló egyik osztály az <code>ArrayList</code>. Az alábbi példában a képernyőről olvasott karakterláncokat írjuk ki fordított sorrendben:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">ArrayList</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span> lista <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayList</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Adj meg ot szot!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">try</span> <span class="token punctuation">{</span>
		<span class="token keyword">for</span><span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i<span class="token operator">&lt;</span><span class="token number">5</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
			<span class="token class-name">String</span> szo <span class="token operator">=</span> r<span class="token punctuation">.</span><span class="token function">readLine</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
			lista<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>szo<span class="token punctuation">)</span><span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span> <span class="token keyword">catch</span><span class="token punctuation">(</span><span class="token class-name">IOException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token class-name">System</span><span class="token punctuation">.</span>err<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>e<span class="token punctuation">.</span><span class="token function">getMessage</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token class-name">ListIterator</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span> lit <span class="token operator">=</span> lista<span class="token punctuation">.</span><span class="token function">listIterator</span><span class="token punctuation">(</span>lista<span class="token punctuation">.</span><span class="token function">size</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">while</span><span class="token punctuation">(</span>lit<span class="token punctuation">.</span><span class="token function">hasPrevious</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token class-name">String</span> str <span class="token operator">=</span>  lit<span class="token punctuation">.</span><span class="token function">previous</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
		<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>str<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,341),l=[o];function p(i,c){return n(),s("div",null,l)}const r=a(t,[["render",p],["__file","lesson1.html.vue"]]);export{r as default};
